local GAME = "blox-fruit" _G._TAG = GAME if _G.bf_shutdown then pcall(_G.bf_shutdown) end require("./i18n") require("./config") require("./modules/function_manager") require("./modules/flow_lock") require("./modules/bring_system") require("./modules/fast_attacks") require("./modules/combat_core") require("./modules/get_quest") require("./modules/get_saber") require("./modules/reach_new_seas") require("./modules/tool") require("./modules/tween_service") require("./modules/fly") require("./modules/auto_farm") require("./modules/diag") require("./modules/extra") require("./gui") _G.bf_help = function() local i18n = _G.bf_i18n print("[bf] === info ===") i18n.help("help.info") print("[bf] === bring ===") i18n.help("help.bring") print("[bf] === attack ===") i18n.help("help.attack") print("[bf] === quest ===") i18n.help("help.quest") print("[bf] === tween ===") i18n.help("help.tween") print("[bf] _G.bf_help()") end _G.bf_shutdown = function() local shutdown = _G.bf_shutdown _G.bf_shutdown = nil if _G.SP_BF_CLEANUPS then for i = #_G.SP_BF_CLEANUPS, 1, -1 do if type(_G.SP_BF_CLEANUPS[i]) == "function" then pcall(_G.SP_BF_CLEANUPS[i]) end end _G.SP_BF_CLEANUPS = nil end for _, name in ipairs({ "bf_farm", "bf_bring", "bf_combat", "bf_attack", "bf_quest", "bf_saber", "bf_seas", "bf_tool", "bf_tween", "bf_fly", "bf_diag", "bf_extra", "bf_flow", }) do local m = _G[name] if m and m.stop then pcall(m.stop) end end if _G.bf_gui then pcall(_G.bf_gui.destroy) end end _G.BF_CLEANUP = _G.bf_shutdown if _G.bf_info then _G.bf_info() end]] __src["./i18n"] = [[
local TAG = "[" .. (_G._TAG or "?") .. "/i18n]" local locales = {} locales.zh = require("./locale/zh") locales.en = require("./locale/en") local defaultLocale = locales.zh or locales.en local function normalizeLang(value) value = tostring(value or ""):lower() if value:sub(1, 2) == "zh" or value:find("chinese", 1, true) then return "zh" end if value:sub(1, 2) == "en" or value:find("english", 1, true) then return "en" end return nil end local function detectSystemLang() local probes = {} local okLoc, loc = pcall(function() return game:GetService("LocalizationService") end) if okLoc and loc then probes[#probes + 1] = function() return loc.SystemLocaleId end probes[#probes + 1] = function() return loc.RobloxLocaleId end end probes[#probes + 1] = function() local players = game:GetService("Players") return players.LocalPlayer and players.LocalPlayer.LocaleId end probes[#probes + 1] = function() return _G.env and _G.env.LANG end for _, probe in ipairs(probes) do local ok, value = pcall(probe) local resolved = ok and normalizeLang(value) or nil if resolved and locales[resolved] then return resolved end end return "zh" end local lang = normalizeLang(_G.SP_BF_LANG) or detectSystemLang() local function translate(key, ...) local locale = locales[lang] or defaultLocale local template = locale[key] or (defaultLocale and defaultLocale[key]) or key if type(template) == "table" then return template end if select("#", ...) > 0 then local ok, result = pcall(string.format, template, ...) return ok and result or template end return template end local M = { setLang = function(newLang) if locales[newLang] then lang = newLang print(TAG .. " → " .. newLang) else local list = {} for k in pairs(locales) do list[#list + 1] = k end print(TAG .. " unknown: " .. newLang .. " | available: " .. table.concat(list, ", ")) end end, getLang = function() return lang end, help = function(key) local lines = translate(key) if type(lines) == "table" then for _, line in ipairs(lines) do print(line) end end end, } setmetatable(M, { __call = function(_, key, ...) return translate(key, ...) end }) _G.bf_i18n = M print(TAG .. " " .. lang) return M]] __src["./locale/zh"] = [[
