local TAG = "[bf/fm]" local i18n = _G.bf_i18n local M = {} local registry = {} function M.register(name, fn) if type(name) ~= "string" or type(fn) ~= "function" then warn(TAG .. " register: bad args " .. tostring(name)) return end registry[name] = fn end function M.call(name, ...) local fn = registry[name] if not fn then warn(TAG .. " function not found: " .. tostring(name)) return nil end local ok, r1, r2, r3 = pcall(fn, ...) if not ok then warn(TAG .. " call " .. name .. " failed: " .. tostring(r1)) return nil end return r1, r2, r3 end function M.list() local names = {} for n in pairs(registry) do table.insert(names, n) end table.sort(names) return names end local function getPos(x) if not x then return nil end if typeof(x) == "Vector3" then return x end if typeof(x) == "CFrame" then return x.Position end if typeof(x) == "Instance" then if x:IsA("BasePart") then return x.Position end if x:IsA("Model") then local hrp = x:FindFirstChild("HumanoidRootPart") or x.PrimaryPart if hrp then return hrp.Position end end end return nil end function M.GetDistance(a, b) local pa, pb = getPos(a), getPos(b) if not pa or not pb then return math.huge end return (pa - pb).Magnitude end function M.getHRP() local lp = game.Players.LocalPlayer local char = lp and lp.Character return char and char:FindFirstChild("HumanoidRootPart") end function M.getHumanoid() local lp = game.Players.LocalPlayer local char = lp and lp.Character return char and char:FindFirstChildOfClass("Humanoid") end function M.getLevel() local lp = game.Players.LocalPlayer local data = lp and lp:FindFirstChild("Data") local lv = data and data:FindFirstChild("Level") return (lv and lv.Value) or 0 end function M.getBeli() local lp = game.Players.LocalPlayer local data = lp and lp:FindFirstChild("Data") local b = data and data:FindFirstChild("Beli") return (b and b.Value) or 0 end function M.getFragments() local lp = game.Players.LocalPlayer local data = lp and lp:FindFirstChild("Data") local f = data and data:FindFirstChild("Fragments") return (f and f.Value) or 0 end function M.getRace() local lp = game.Players.LocalPlayer local data = lp and lp:FindFirstChild("Data") local r = data and data:FindFirstChild("Race") return (r and r.Value) or "" end function M.getDevilFruit() local lp = game.Players.LocalPlayer local data = lp and lp:FindFirstChild("Data") local df = data and data:FindFirstChild("DevilFruit") return (df and df.Value) or "" end function M.getStatLevel(statName) local lp = game.Players.LocalPlayer local data = lp and lp:FindFirstChild("Data") local stats = data and data:FindFirstChild("Stats") if not stats then return 0 end local s = stats:FindFirstChild(statName) local lv = s and s:FindFirstChild("Level") return (lv and lv.Value) or 0 end function M.getStatPoints() local lp = game.Players.LocalPlayer local data = lp and lp:FindFirstChild("Data") local p = data and data:FindFirstChild("Points") return (p and p.Value) or 0 end function M.getRemotes() return game:GetService("ReplicatedStorage"):FindFirstChild("Remotes") end function M.CommF(...) local r = M.getRemotes() local cf = r and r:FindFirstChild("CommF") if not cf then return nil end local ok, res = pcall(function(...) return cf:InvokeServer(...) end, ...) return ok and res or nil end function M.CommF_(...) local r = M.getRemotes() local cf = r and r:FindFirstChild("CommF_") if not cf then return nil end local ok, res = pcall(function(...) return cf:InvokeServer(...) end, ...) return ok and res or nil end function M.CommE(...) local r = M.getRemotes() local ce = r and r:FindFirstChild("CommE") if not ce then return false end local ok = pcall(function(...) ce:FireServer(...) end, ...) return ok end _G.bf = _G.bf or {} _G.bf.info = function() print(i18n("info.title")) print(string.format(i18n("info.placeid"), tostring(game.PlaceId))) print(string.format(i18n("info.level"), tostring(M.getLevel()), tostring(M.getBeli()), tostring(M.getFragments()))) print(string.format(i18n("info.race"), M.getRace(), M.getDevilFruit() ~= "" and M.getDevilFruit() or "-")) print(string.format(i18n("info.stats"), M.getStatLevel("Melee"), M.getStatLevel("Sword"), M.getStatLevel("Gun"), M.getStatLevel("Demon Fruit"), M.getStatLevel("Defense"), M.getStatPoints())) print(TAG .. " 已注册函数: " .. tostring(#M.list())) end _G.bf_info = _G.bf.info _G.bf_fm = M print(TAG .. " " .. i18n("loaded")) return M]] __src["./modules/flow_lock"] = [[
local TAG = "[bf/flow]" local M = {} local activeOwner = nil local activeReason = nil local activeSince = 0 local PRIORITY = { manual = 100, sea = 90, boss = 80, quest = 60, tween = 50, farm = 30, misc = 10, } local function store() _G.SP_BF_MODULES = _G.SP_BF_MODULES or {} return _G.SP_BF_MODULES end local function setStoredOwner(owner, reason) local s = store() s._active_flow = owner s._active_flow_reason = reason s._sea_flow_active = owner == "sea" end local function clearStoredOwner(owner) local s = store() if not owner or s._active_flow == owner then s._active_flow = nil s._active_flow_reason = nil s._sea_flow_active = false end end function M.owner() local s = _G.SP_BF_MODULES return activeOwner or (s and s._active_flow) or nil end function M.isOwner(owner) return owner ~= nil and M.owner() == owner end function M.isLockedFor(owner) local current = M.owner() return current ~= nil and current ~= owner end function M.priority(owner) return PRIORITY[owner] or PRIORITY.misc end function M.canPreempt(owner, current) if not current or current == owner then return true end return M.priority(owner) > M.priority(current) end function M.setPriority(owner, priority) if type(owner) == "string" and type(priority) == "number" then PRIORITY[owner] = priority end end function M.claim(owner, opts) opts = opts or {} if type(owner) ~= "string" or owner == "" then return false, "bad_owner" end local current = M.owner() if current and current ~= owner and not opts.force and not M.canPreempt(owner, current) then return false, current end if current and current ~= owner and opts.quiet ~= true then print(TAG .. " preempt " .. tostring(current) .. " -> " .. owner .. " (" .. tostring(M.priority(current)) .. " < " .. tostring(M.priority(owner)) .. ")") end activeOwner = owner activeReason = opts.reason activeSince = os.clock() setStoredOwner(owner, activeReason) if opts.quiet ~= true then print(TAG .. " owner=" .. owner .. (activeReason and (" reason=" .. tostring(activeReason)) or "")) end return true end function M.release(owner) local current = M.owner() if owner and current and current ~= owner then return false, current end clearStoredOwner(owner) activeOwner = nil activeReason = nil activeSince = 0 return true end function M.stopConflicts(owner) if owner == "sea" then if _G.bf_farm and _G.bf_farm.stop then pcall(function() _G.bf_farm.stop("flow_sea") end) end if _G.bf_quest and _G.bf_quest.stop then pcall(function() _G.bf_quest.stop() end) end if _G.bf_bring and _G.bf_bring.stop then pcall(function() _G.bf_bring.stop() end) end if _G.bf_combat and _G.bf_combat.stop then pcall(function() _G.bf_combat.stop("farm", true) end) end if _G.bf_attack and _G.bf_attack.stop then pcall(function() _G.bf_attack.stop() end) end return true end if owner == "farm" then local current = M.owner() if current and current ~= "farm" and not M.canPreempt("farm", current) then return false, current end if _G.bf_quest and _G.bf_quest.stop then pcall(function() _G.bf_quest.stop() end) end return true end return true end function M.status() local owner = M.owner() local age = owner and math.floor(os.clock() - (activeSince or os.clock())) or 0 print(TAG .. " owner=" .. tostring(owner or "none") .. " priority=" .. tostring(owner and M.priority(owner) or "-") .. " reason=" .. tostring(activeReason or "-") .. " age=" .. tostring(age) .. "s") end function M.stop() M.release(activeOwner) end _G.bf_flow = M print(TAG .. " loaded") return M]] __src["./modules/bring_system"] = [[
local TAG = "[bf/bring]" local i18n = _G.bf_i18n local fm = _G.bf_fm local cfg = _G.bf_config local RunService = game:GetService("RunService") local M = {} local MODULE_TOKEN = {} _G.SP_BF_BRING_TOKEN = MODULE_TOKEN local running = false local connection = nil local touched = setmetatable({}, { __mode = "k" }) local TICK_INTERVAL = math.max(0.05, tonumber(cfg.BRING_TICK_INTERVAL) or 0.15) local TOUCHED_PURGE_INTERVAL = math.max(1, tonumber(cfg.BRING_TOUCHED_PURGE_INTERVAL) or 3) local lastTouchedPurgeAt = -math.huge local config = { distance = cfg.BRING_DEFAULT_DISTANCE, mobName = nil, teleport = true, stackFront = 8, stackJitter = 3, safeMode = cfg.BRING_SAFE_MODE ~= false, maxPulls = math.max(1, math.min(8, tonumber(cfg.BRING_MAX_PULLS) or 3)), mode = "player", anchorMob = nil, anchorStackPos = nil, gatherRadius = 80, } local lastStats = { pulled = 0, missed = 0, candidates = 0, owned = 0, limited = 0, farthest = 0, touched = 0, } local function isFiniteNumber(n) return type(n) == "number" and n == n and n > -math.huge and n < math.huge end local function isUsablePos(pos) if typeof(pos) ~= "Vector3" then return false end if not isFiniteNumber(pos.X) or not isFiniteNumber(pos.Y) or not isFiniteNumber(pos.Z) then return false end if pos.Y < -1000 or pos.Y > 20000 then return false end if math.abs(pos.X) > 100000 or math.abs(pos.Z) > 100000 then return false end return true end local function isInMyNetwork(part) if not part or not isUsablePos(part.Position) then return false end if type(isnetworkowner) ~= "function" then return fm.GetDistance(part.Position, fm.getHRP() and fm.getHRP().Position or Vector3.new(0,0,0)) <= 300 end local ok, res = pcall(isnetworkowner, part) return ok and res or false end local raycastParams = RaycastParams.new() raycastParams.FilterType = Enum.RaycastFilterType.Exclude local function getStackPos() if config.mode == "anchor" and config.anchorStackPos then return config.anchorStackPos end local hrp = fm.getHRP() if not hrp then return nil end local fwd = hrp.CFrame.LookVector local horFwd = Vector3.new(fwd.X, 0, fwd.Z) if horFwd.Magnitude < 0.01 then horFwd = Vector3.new(0, 0, -1) else horFwd = horFwd.Unit end local front = hrp.Position + horFwd * config.stackFront local lp = game.Players.LocalPlayer raycastParams.FilterDescendantsInstances = { workspace:FindFirstChild("Enemies"), lp.Character, } local origin = front + Vector3.new(0, 200, 0) local hit = workspace:Raycast(origin, Vector3.new(0, -400, 0), raycastParams) if hit then return Vector3.new(front.X, hit.Position.Y + 3, front.Z) end return Vector3.new(front.X, hrp.Position.Y - 5, front.Z) end local function getMobOffset(idx) local gx = (idx % 5) - 2 local gz = math.floor(idx / 5) - 2 return Vector3.new(gx * config.stackJitter, 0, gz * config.stackJitter) end local function snapshotMob(mob) if touched[mob] then return end local hrp = mob:FindFirstChild("HumanoidRootPart") touched[mob] = { origSize = hrp and hrp.Size, origCanCollide = hrp and hrp.CanCollide, origAnchored = hrp and hrp.Anchored, } end local function restoreMob(mob) local snap = touched[mob] if not snap then return end local hrp = mob:FindFirstChild("HumanoidRootPart") if hrp then if snap.origSize then pcall(function() hrp.Size = snap.origSize end) end if snap.origCanCollide ~= nil then pcall(function() hrp.CanCollide = snap.origCanCollide end) end if snap.origAnchored ~= nil then pcall(function() hrp.Anchored = snap.origAnchored end) end local bp = hrp:FindFirstChild("BF_BringBP") if bp then pcall(function() bp:Destroy() end) end end touched[mob] = nil end local function purgeTouched() local now = os.clock() if now - lastTouchedPurgeAt < TOUCHED_PURGE_INTERVAL then return end lastTouchedPurgeAt = now for mob in pairs(touched) do if not mob or not mob.Parent then touched[mob] = nil else local hum = mob:FindFirstChildOfClass("Humanoid") if not hum or hum.Health <= 0 then restoreMob(mob) end end end end local function restoreAll() for mob in pairs(touched) do if mob and mob.Parent then restoreMob(mob) end end touched = setmetatable({}, { __mode = "k" }) local enemies = workspace:FindFirstChild("Enemies") if enemies then for _, mob in ipairs(enemies:GetChildren()) do local hrp = mob:FindFirstChild("HumanoidRootPart") local bp = hrp and hrp:FindFirstChild("BF_BringBP") if bp then pcall(function() bp:Destroy() end) end end end end local function countTouched() local n = 0 for _ in pairs(touched) do n = n + 1 end return n end local function horizontalDistance(a, b) if not isUsablePos(a) or not isUsablePos(b) then return math.huge end local dx = a.X - b.X local dz = a.Z - b.Z return math.sqrt(dx * dx + dz * dz) end local function pullMob(mob, targetPos) local hrp = mob:FindFirstChild("HumanoidRootPart") if not hrp then return false end if not isUsablePos(hrp.Position) or not isUsablePos(targetPos) then restoreMob(mob) return false end if isInMyNetwork(hrp) then snapshotMob(mob) pcall(function() hrp.CanCollide = false end) if not config.safeMode then pcall(function() hrp.Size = Vector3.new(4, 4, 4) end) end local bp = hrp:FindFirstChild("BF_BringBP") if not bp then bp = Instance.new("BodyPosition") bp.Name = "BF_BringBP" bp.MaxForce = Vector3.new(1, 1, 1) * (config.safeMode and 4e5 or 1e6) bp.P = config.safeMode and 2600 or 5000 bp.D = config.safeMode and 350 or 200 bp.Parent = hrp end bp.Position = targetPos return true else restoreMob(mob) return false end end local function bringTick() local enemies = workspace:FindFirstChild("Enemies") if not enemies then return 0, 0 end local myHRP = fm.getHRP() if not myHRP then return 0, 0 end local stackPos = getStackPos() if not stackPos then return 0, 0 end local anchorPos = nil if config.mode == "anchor" and config.anchorStackPos then anchorPos = config.anchorStackPos end local pulled, missed, candidates, owned, limited = 0, 0, 0, 0, 0 local activeTouched = {} local farthest = 0 local idx = 0 for _, mob in ipairs(enemies:GetChildren()) do local hrp = mob:FindFirstChild("HumanoidRootPart") local hum = mob:FindFirstChildOfClass("Humanoid") if hrp and hum and hum.Health > 0 and isUsablePos(hrp.Position) then local distFromMe = (hrp.Position - myHRP.Position).Magnitude local nameOK = (config.mobName == nil) or (mob.Name == config.mobName) local inRange = false local rangeDist = distFromMe if anchorPos then local delta = hrp.Position - anchorPos local distFromAnchor = Vector3.new(delta.X, 0, delta.Z).Magnitude rangeDist = distFromAnchor inRange = (mob == config.anchorMob) or (distFromAnchor <= config.gatherRadius and distFromAnchor > 0) else inRange = distFromMe <= config.distance and distFromMe > cfg.BRING_MIN_DISTANCE end if nameOK and inRange then candidates = candidates + 1 if rangeDist > farthest and rangeDist < math.huge then farthest = rangeDist end if mob == config.anchorMob then restoreMob(mob) else local hasOwner = isInMyNetwork(hrp) if hasOwner then owned = owned + 1 end if idx >= config.maxPulls then missed = missed + 1 limited = limited + 1 continue end local targetPos = stackPos + getMobOffset(idx) idx = idx + 1 if hasOwner and pullMob(mob, targetPos) then activeTouched[mob] = true pulled = pulled + 1 else missed = missed + 1 end end end end end for mob in pairs(touched) do if not activeTouched[mob] then restoreMob(mob) end end lastStats = { pulled = pulled, missed = missed, candidates = candidates, owned = owned, limited = limited, farthest = farthest, touched = countTouched(), gather = config.gatherRadius, maxPulls = config.maxPulls, mode = config.mode, mob = config.mobName, } return pulled, missed, candidates end local function applyStartConfig(distance, mobName, teleportFlag) config.distance = tonumber(distance) or config.distance config.mobName = mobName if teleportFlag ~= nil then config.teleport = teleportFlag end end function M.start(distance, mobName, teleportFlag) if running then applyStartConfig(distance, mobName, teleportFlag) print(TAG .. string.format(" running=true, 已更新拉怪参数 (dist=%d, mob=%s)", config.distance, tostring(config.mobName))) return end restoreAll() applyStartConfig(distance, mobName, teleportFlag) print(TAG .. " " .. i18n("bring.start") .. string.format(" (dist=%d, mob=%s, stack=前方%dm, 地面)", config.distance, tostring(config.mobName), config.stackFront)) running = true local lastLog = 0 local lastRun = 0 connection = RunService.Heartbeat:Connect(function() if _G.SP_BF_BRING_TOKEN ~= MODULE_TOKEN then M.stop() return end if not running then return end local now = tick() if now - lastRun < TICK_INTERVAL then return end lastRun = now purgeTouched() local p, miss, candidates = bringTick() if (p + miss) > 0 and (now - lastLog) > 2 then lastLog = now print(TAG .. string.format(" pulled=%d missed=%d candidates=%d owned=%d limited=%d farthest=%dm gather=%d safe=%s", p, miss, candidates or 0, lastStats.owned or 0, lastStats.limited or 0, math.floor(lastStats.farthest or 0), config.gatherRadius, tostring(config.safeMode))) end end) end function M.stop() if not running then return end running = false if connection then connection:Disconnect(); connection = nil end restoreAll() print(TAG .. " " .. i18n("bring.stop")) end function M.setDistance(d) config.distance = math.max(1, math.floor(d or cfg.BRING_DEFAULT_DISTANCE)) end function M.setMobName(n) config.mobName = (n and n ~= "" and n) or nil end function M.setTeleport(b) config.teleport = b and true or false end function M.setStackFront(f) config.stackFront = math.max(3, tonumber(f) or 8) end function M.setSafeMode(b) config.safeMode = b ~= false end function M.setMaxPulls(n) config.maxPulls = math.max(1, math.min(8, tonumber(n) or config.maxPulls)) end _G.SP_BF_CLEANUPS = _G.SP_BF_CLEANUPS or {} table.insert(_G.SP_BF_CLEANUPS, function() M.stop() end) function M.setAnchorMob(mob, gatherRadius, fixedStackPos) if mob and mob.Parent then local ahrp = mob:FindFirstChild("HumanoidRootPart") if not ahrp then warn(TAG .. " setAnchorMob: mob 没 HRP") return end if not isUsablePos(ahrp.Position) then warn(TAG .. " setAnchorMob: mob 坐标无效, 已跳过") M.clearAnchor() return end if config.anchorMob ~= mob then restoreAll() end config.mode = "anchor" config.anchorMob = mob config.mobName = mob.Name if gatherRadius then config.gatherRadius = math.max(10, tonumber(gatherRadius) or 80) end if isUsablePos(fixedStackPos) then config.anchorStackPos = fixedStackPos else raycastParams.FilterDescendantsInstances = { workspace:FindFirstChild("Enemies"), game.Players.LocalPlayer.Character, } local origin = ahrp.Position + Vector3.new(0, 35, 0) local hit = workspace:Raycast(origin, Vector3.new(0, -120, 0), raycastParams) if hit then local y = hit.Position.Y + 3 if y > ahrp.Position.Y + 12 or y < ahrp.Position.Y - 25 then y = ahrp.Position.Y end config.anchorStackPos = Vector3.new(ahrp.Position.X, y, ahrp.Position.Z) else config.anchorStackPos = ahrp.Position end end if not isUsablePos(config.anchorStackPos) then warn(TAG .. " setAnchorMob: stack 坐标无效, 已清理") M.clearAnchor() return end print(TAG .. " setAnchorMob=" .. mob.Name .. " stackPos=(" .. math.floor(config.anchorStackPos.X) .. "," .. math.floor(config.anchorStackPos.Y) .. "," .. math.floor(config.anchorStackPos.Z) .. ") gather=" .. config.gatherRadius .. "m") else config.mode = "player" config.anchorMob = nil config.anchorStackPos = nil end end function M.setGatherRadius(r) config.gatherRadius = math.max(10, math.min(500, tonumber(r) or 80)) end function M.getGatherRadius() return config.gatherRadius end function M.clearAnchor() restoreAll() config.mode = "player" config.anchorMob = nil config.anchorStackPos = nil config.mobName = nil end function M.getAnchor() return config.anchorMob end function M.getStackPos() return config.anchorStackPos end function M.getLastStats() local out = {} for k, v in pairs(lastStats) do out[k] = v end out.touched = countTouched() return out end function M.scan(radius) local enemies = workspace:FindFirstChild("Enemies") local myHRP = fm.getHRP() local stackPos = getStackPos() local scanRadius = math.max(10, math.min(500, tonumber(radius) or config.gatherRadius)) local out = { pulled = 0, missed = 0, candidates = 0, owned = 0, limited = 0, farthest = 0, touched = countTouched(), gather = scanRadius, maxPulls = config.maxPulls, mode = config.mode, mob = config.mobName, } if enemies and myHRP and stackPos then local anchorPos = config.mode == "anchor" and config.anchorStackPos or nil for _, mob in ipairs(enemies:GetChildren()) do local hrp = mob:FindFirstChild("HumanoidRootPart") local hum = mob:FindFirstChildOfClass("Humanoid") if hrp and hum and hum.Health > 0 and isUsablePos(hrp.Position) then local nameOK = (config.mobName == nil) or (mob.Name == config.mobName) local rangeDist = anchorPos and horizontalDistance(hrp.Position, anchorPos) or (hrp.Position - myHRP.Position).Magnitude local inRange = anchorPos and ((mob == config.anchorMob) or (rangeDist <= scanRadius and rangeDist > 0)) or (rangeDist <= config.distance and rangeDist > cfg.BRING_MIN_DISTANCE) if nameOK and inRange then out.candidates = out.candidates + 1 if rangeDist > out.farthest and rangeDist < math.huge then out.farthest = rangeDist end if mob ~= config.anchorMob and isInMyNetwork(hrp) then out.owned = out.owned + 1 end end end end end print(TAG .. string.format(" scan radius=%d candidates=%d owned=%d pulled=%d missed=%d limited=%d farthest=%dm touched=%d", out.gather or scanRadius, out.candidates or 0, out.owned or 0, out.pulled or 0, out.missed or 0, out.limited or 0, math.floor(out.farthest or 0), out.touched or 0)) return out end function M.isRunning() return running end function M.status() print(TAG .. " running=" .. tostring(running) .. " mode=" .. config.mode .. " dist=" .. config.distance .. " gather=" .. config.gatherRadius .. " mob=" .. tostring(config.mobName) .. " stackFront=" .. config.stackFront .. " safe=" .. tostring(config.safeMode) .. " maxPulls=" .. tostring(config.maxPulls) .. " last=" .. tostring(lastStats.pulled) .. "/" .. tostring(lastStats.missed) .. "/" .. tostring(lastStats.candidates) .. " owned=" .. tostring(lastStats.owned) .. " limited=" .. tostring(lastStats.limited) .. " farthest=" .. tostring(math.floor(lastStats.farthest or 0)) .. " touched=" .. tostring(countTouched())) end fm.register("BringTick", bringTick) fm.register("BringScan", M.scan) fm.register("IsInMyNetwork", isInMyNetwork) fm.register("GetStackPos", getStackPos) _G.bf_bring = M print(TAG .. " " .. i18n("loaded")) return M]] __src["./modules/fast_attacks"] = [[
local TAG = "[bf/attack]" local i18n = _G.bf_i18n local fm = _G.bf_fm local cfg = _G.bf_config local RunService = game:GetService("RunService") local M = {} local MODULE_TOKEN = {} _G.SP_BF_ATTACK_TOKEN = MODULE_TOKEN local running = false local connection = nil local lastEquipWarnAt = -math.huge local lastAuraEnsureAt = -math.huge local lastAuraLogAt = -math.huge local auraPurchaseAttempted = false local config = { range = cfg.ATTACK_RANGE, tick_interval = math.max(0.03, tonumber(cfg.FAST_ATTACK_INTERVAL) or 0.5), weapon = "Combat", weapon_class = "melee", } local MAX_TARGETS_PER_TICK = math.max(1, math.min(3, tonumber(cfg.MAX_ATTACK_TARGETS) or tonumber(cfg.AOE_PRIMARY_HITS) or 3)) local MAX_PRIMARY_HITS_PER_TICK = math.max(1, math.min(MAX_TARGETS_PER_TICK, tonumber(cfg.AOE_PRIMARY_HITS) or 3)) local targetProvider = nil local targetFilter = nil local function getAttackSweepRange() return math.max(config.range or 0, cfg.ATTACK_RANGE or 60, 90) end local function getCommF() local remotes = game:GetService("ReplicatedStorage"):FindFirstChild("Remotes") return remotes and remotes:FindFirstChild("CommF_") or nil end local function hasActiveAura() local lp = game.Players.LocalPlayer local char = lp and lp.Character return char and char:FindFirstChild("HasBuso") ~= nil end local function commF(...) local remote = getCommF() if not remote then return false, "no_commf" end local args = { ... } local ok, res = pcall(function() return remote:InvokeServer(unpack(args)) end) return ok, res end local function ensureAura() if cfg.AUTO_AURA_ENABLED == false then return true end if hasActiveAura() then return true end local now = os.clock() if now - lastAuraEnsureAt < 2 then return hasActiveAura() end lastAuraEnsureAt = now local ok, res = commF("Buso") if not hasActiveAura() and cfg.AUTO_BUY_AURA ~= false and not auraPurchaseAttempted then local beli = fm.getBeli and fm.getBeli() or 0 if beli >= (tonumber(cfg.AURA_COST) or 25000) then auraPurchaseAttempted = true commF("BuyHaki", "Buso") ok, res = commF("Buso") end end if hasActiveAura() then if now - lastAuraLogAt >= 10 then lastAuraLogAt = now print(TAG .. " Aura/Buso 已开启, 物理攻击可命中元素怪") end return true end if now - lastAuraLogAt >= 5 then lastAuraLogAt = now warn(TAG .. " Aura/Buso 未开启, 元素怪会免疫物理攻击 result=" .. tostring(ok) .. "/" .. tostring(res)) end return false end local function passesTargetFilter(mob) if type(targetFilter) ~= "function" then return true end local ok, allowed = pcall(targetFilter, mob) return ok and allowed == true end local function isFiniteNumber(n) return type(n) == "number" and n == n and n > -math.huge and n < math.huge end local function isUsablePos(pos) if typeof(pos) ~= "Vector3" then return false end if not isFiniteNumber(pos.X) or not isFiniteNumber(pos.Y) or not isFiniteNumber(pos.Z) then return false end if pos.Y < -1000 or pos.Y > 20000 then return false end if math.abs(pos.X) > 100000 or math.abs(pos.Z) > 100000 then return false end return true end local function isNetworkOwnedPart(part) if not part or not isUsablePos(part.Position) then return false end if type(isnetworkowner) ~= "function" then return true end local ok, res = pcall(isnetworkowner, part) return ok and res == true end local MELEE_NAMES = { Combat = true, ["Black Leg"] = true, Electro = true, ["Fishman Karate"] = true, ["Dragon Talon"] = true, ["Death Step"] = true, ["Sharkman Karate"] = true, ["Electric Claw"] = true, Superhuman = true, Godhuman = true, ["Dragon Claw"] = true, } local SWORD_NAMES = { Pipe = true, Cutlass = true, Bisento = true, Saber = true, ["Dual Katana"] = true, ["Triple Katana"] = true, Wando = true, Katana = true, Soul = true, ["Shark Saw"] = true, ["Dual-Headed Blade"] = true, ["Tushita"] = true, ["Yama"] = true, ["Hallow Scythe"] = true, ["Dark Dagger"] = true, ["Pole (1st Form)"] = true, ["Pole (2nd Form)"] = true, ["Twin Hooks"] = true, ["Iron Mace"] = true, ["Soul Cane"] = true, } local GUN_NAMES = { Slingshot = true, Flintlock = true, ["Refined Slingshot"] = true, ["Refined Flintlock"] = true, Musket = true, Cannon = true, Bazooka = true, Kabucha = true, ["Soul Guitar"] = true, } local function findWeaponByClass(class) local lp = game.Players.LocalPlayer local function pickFrom(parent, table) for _, t in ipairs(parent:GetChildren()) do if t:IsA("Tool") and table[t.Name] then return t end end return nil end local pool = (class == "melee") and MELEE_NAMES or (class == "sword") and SWORD_NAMES or GUN_NAMES if lp.Character then local t = pickFrom(lp.Character, pool) if t then return t.Name end end local bp = lp:FindFirstChild("Backpack") if bp then local t = pickFrom(bp, pool) if t then return t.Name end end return nil end local function getEquippedTool() local char = game.Players.LocalPlayer.Character if not char then return nil end return char:FindFirstChildOfClass("Tool") end local _registerHit, _registerAttack = nil, nil local function getNetRemotes() if _registerHit and _registerHit.Parent and _registerAttack and _registerAttack.Parent then return _registerHit, _registerAttack end local RS = game:GetService("ReplicatedStorage") local m = RS:FindFirstChild("Modules") local n = m and m:FindFirstChild("Net") if not n then return nil, nil end _registerHit = n:FindFirstChild("RE/RegisterHit") _registerAttack = n:FindFirstChild("RE/RegisterAttack") return _registerHit, _registerAttack end local _lastAttackFireAt = 0 local attackSyncPeriod = math.max(0.03, tonumber(cfg.REGISTER_ATTACK_INTERVAL) or 0.5) local _combatController = nil local _lastControllerScanAt = -math.huge local _lastToolActivateAt = 0 local _lastHitboxWarnAt = -math.huge local patchedHitboxes = {} local function getOfficialHitboxRange() return math.min(math.max(getAttackSweepRange(), cfg.OFFICIAL_HITBOX_RANGE or 90), cfg.OFFICIAL_HITBOX_RANGE_MAX or 120) end local function looksLikeCombatController(t) if type(t) ~= "table" then return false end return type(rawget(t, "GetWeaponData")) == "function" and type(rawget(t, "RunHitDetection")) == "function" and type(rawget(t, "AttackStart")) == "function" end local function getCombatController() if looksLikeCombatController(_combatController) then return _combatController end if looksLikeCombatController(_G.__bf_ctrl) then _combatController = _G.__bf_ctrl return _combatController end if type(getgc) ~= "function" then return nil end local now = os.clock() if now - _lastControllerScanAt < 5 then return nil end _lastControllerScanAt = now local ok, objects = pcall(getgc, true) if not ok or type(objects) ~= "table" then return nil end for _, obj in ipairs(objects) do if looksLikeCombatController(obj) then local info = debug and debug.getinfo and debug.getinfo(rawget(obj, "GetWeaponData")) or nil local src = info and tostring(info.source or "") or "" if src == "" or src:find("CombatUtil", 1, true) then _combatController = obj _G.__bf_ctrl = obj return _combatController end end end return nil end local function patchOfficialHitbox() local ctrl = getCombatController() if not ctrl then local now = os.clock() if now - _lastHitboxWarnAt > 8 then _lastHitboxWarnAt = now warn(TAG .. " 未找到 CombatUtil 控制器, 暂时只能裸发 RegisterHit") end return false, "no_combat_controller" end local weapon = M.weapon() if not weapon or weapon == "(无)" then return false, "no_weapon" end local ok, data = pcall(function() return ctrl:GetWeaponData(weapon) end) if not ok or type(data) ~= "table" then return false, "no_weapon_data" end local desired = getOfficialHitboxRange() local old = tonumber(data.HitboxMagnitude) or 0 if old < desired then if patchedHitboxes[data] == nil then patchedHitboxes[data] = old end data.HitboxMagnitude = desired end return true, "official_hitbox(" .. tostring(math.floor(desired)) .. ")" end local function restoreOfficialHitboxes() for data, old in pairs(patchedHitboxes) do if type(data) == "table" then pcall(function() data.HitboxMagnitude = old end) end end patchedHitboxes = {} end local function activateEquippedTool() local tool = getEquippedTool() if not tool then return false, "no_tool" end local now = tick() if now - _lastToolActivateAt < attackSyncPeriod then return true, "tool_activate_cached" end _lastToolActivateAt = now local ok, err = pcall(function() tool:Activate() end) if not ok then return false, "tool_activate_err:" .. tostring(err):sub(1, 40) end return true, "tool_activate" end local function pickBodyPart(mob) for _, name in ipairs({"LeftHand","UpperTorso","Head","RightHand","LowerTorso","HumanoidRootPart","Torso"}) do local p = mob:FindFirstChild(name) if p and p:IsA("BasePart") and isUsablePos(p.Position) then return p end end for _, c in ipairs(mob:GetChildren()) do if c:IsA("BasePart") and isUsablePos(c.Position) then return c end end return nil end local function getBringStackPos() if _G.bf_bring and _G.bf_bring.getStackPos then local ok, pos = pcall(_G.bf_bring.getStackPos) if ok and typeof(pos) == "Vector3" then return pos end end return nil end local function collectHitList(primaryTarget, primaryPart, targets) local hitList = {} local seen = {} local function add(mob, part) if #hitList >= MAX_TARGETS_PER_TICK then return end if mob and part and not seen[mob] and passesTargetFilter(mob) then seen[mob] = true table.insert(hitList, { mob, part }) end end add(primaryTarget, primaryPart) if targets then for _, item in ipairs(targets) do add(item.mob, item.part) end end local enemies = workspace:FindFirstChild("Enemies") if not enemies then return hitList end local centerPart = primaryTarget:FindFirstChild("HumanoidRootPart") or primaryPart if not centerPart then return hitList end local center = centerPart.Position if not isUsablePos(center) then return hitList end local maxDist = math.min(math.max(getAttackSweepRange(), 10), 120) for _, mob in ipairs(enemies:GetChildren()) do if mob ~= primaryTarget then local hum = mob:FindFirstChildOfClass("Humanoid") local part = pickBodyPart(mob) local hrp = mob:FindFirstChild("HumanoidRootPart") or part if hum and hum.Health > 0 and part and hrp and isUsablePos(hrp.Position) and (hrp.Position - center).Magnitude <= maxDist then add(mob, part) end end end return hitList end local function fireRegisterHit(target, targets) if not target or not target.Parent then return false, "no_target" end local part = pickBodyPart(target) if not part then return false, "no_body_part" end local targetHRP = target:FindFirstChild("HumanoidRootPart") or part if not targetHRP or not isUsablePos(targetHRP.Position) then return false, "bad_target_pos" end local rh, ra = getNetRemotes() if not rh or not ra then return false, "no_net_remote" end local now = tick() if (now - _lastAttackFireAt) > attackSyncPeriod then local ok, err = pcall(function() ra:FireServer(attackSyncPeriod) end) if not ok then return false, "register_attack_err:" .. tostring(err):sub(1, 40) end _lastAttackFireAt = now end local hitList = collectHitList(target, part, targets) local ok, err = pcall(function() rh:FireServer(part, hitList) end) if not ok then return false, "register_hit_err:" .. tostring(err):sub(1, 40) end return true, "register_hit(" .. tostring(#hitList) .. ")" end local function findToolInBackpack(name) local bp = game.Players.LocalPlayer:FindFirstChild("Backpack") if not bp then return nil end return bp:FindFirstChild(name) end local function equipTool(name) local hum = fm.getHumanoid() if not hum then return false end local cur = getEquippedTool() if cur and cur.Name == name then return true end local target = findToolInBackpack(name) if not target then local char = game.Players.LocalPlayer.Character target = char and char:FindFirstChild(name) end if not target then return false end pcall(function() hum:EquipTool(target) end) return true end local function ensureWeaponEquipped() local cur = getEquippedTool() local desired = findWeaponByClass(config.weapon_class) if cur and (not desired or cur.Name == desired) then return true end if desired and equipTool(desired) then return true end if cur then return true end local fallback = config.weapon or "Combat" if fallback ~= "" and equipTool(fallback) then return true end local now = os.clock() if now - lastEquipWarnAt > 5 then lastEquipWarnAt = now warn(TAG .. " 当前没有装备武器, 等待背包/角色恢复 " .. tostring(config.weapon_class)) end return false end function M.weapon() local t = getEquippedTool() return t and t.Name or "(无)" end _G.bf = _G.bf or {} _G.bf.weapon = M.weapon local function collectTargets() local hrp = fm.getHRP() if not hrp then return {} end local enemies = workspace:FindFirstChild("Enemies") local targets, seen = {}, {} local stackPos = getBringStackPos() local center = stackPos or hrp.Position local range = getAttackSweepRange() local function addTarget(mob, priority) if not mob or seen[mob] or not mob.Parent then return end if not passesTargetFilter(mob) then return end local hum = mob:FindFirstChildOfClass("Humanoid") local part = pickBodyPart(mob) local mhrp = mob:FindFirstChild("HumanoidRootPart") or part if not hum or hum.Health <= 0 or not part or not mhrp or not isUsablePos(mhrp.Position) then return end local playerDist = (mhrp.Position - hrp.Position).Magnitude local centerDist = (mhrp.Position - center).Magnitude if not priority and playerDist > range and centerDist > range then return end local ownedPenalty = isNetworkOwnedPart(mhrp) and 0 or 20 seen[mob] = true table.insert(targets, { mob = mob, part = part, hrp = mhrp, distance = playerDist, centerDistance = centerDist, score = (priority and -1000 or 0) + math.min(playerDist, centerDist) + ownedPenalty, }) end if targetProvider then local ok, target = pcall(targetProvider) if ok then addTarget(target, true) end end if enemies then for _, mob in ipairs(enemies:GetChildren()) do addTarget(mob, false) end end table.sort(targets, function(a, b) return a.score < b.score end) while #targets > MAX_TARGETS_PER_TICK do table.remove(targets) end return targets end local function chooseTarget() local targets = collectTargets() local first = targets[1] if first then return first.mob, first.distance, targets end local hrp = fm.getHRP() local enemies = workspace:FindFirstChild("Enemies") if not hrp or not enemies then return nil, math.huge, targets end local best, bestDist = nil, math.huge for _, mob in ipairs(enemies:GetChildren()) do local hum = mob:FindFirstChildOfClass("Humanoid") local mhrp = mob:FindFirstChild("HumanoidRootPart") if passesTargetFilter(mob) and hum and hum.Health > 0 and mhrp and isUsablePos(mhrp.Position) then local d = (mhrp.Position - hrp.Position).Magnitude if d < bestDist and d <= cfg.CHOOSE_PROX_SEEK then best, bestDist = mob, d end end end return best, bestDist, targets end _G.SP_BF_CLEANUPS = _G.SP_BF_CLEANUPS or {} table.insert(_G.SP_BF_CLEANUPS, function() M.stop() end) local function fireOnceToTarget(target, targets) local hitboxOk, hitboxSrc = patchOfficialHitbox() local activateOk, activateSrc = false, "skip_activate" if hitboxOk then activateOk, activateSrc = activateEquippedTool() end local ok, src = fireRegisterHit(target, targets) local extraOk, extraTotal = 0, 0 local primaryTotal = ok and 1 or 0 local primaryLimit = targets and math.min(#targets, MAX_PRIMARY_HITS_PER_TICK) or 1 if ok and targets and #targets > 1 and MAX_PRIMARY_HITS_PER_TICK > 1 then local limit = primaryLimit for i = 2, limit do local item = targets[i] if item and item.mob and item.mob.Parent then extraTotal = extraTotal + 1 local ok2 = fireRegisterHit(item.mob, targets) if ok2 then extraOk = extraOk + 1 primaryTotal = primaryTotal + 1 end end end end local parts = { hitboxSrc, activateSrc, src } if extraTotal > 0 then table.insert(parts, "aoe_primary(" .. tostring(extraOk) .. "/" .. tostring(extraTotal) .. ")") end if ok then table.insert(parts, "primary_total(" .. tostring(primaryTotal) .. "/" .. tostring(primaryLimit) .. ",max=" .. tostring(MAX_PRIMARY_HITS_PER_TICK) .. ")") end if ok or activateOk then return true, table.concat(parts, "+") end return false, table.concat(parts, "+") end function M.start() if running then return end ensureAura() if not ensureWeaponEquipped() then return end print(TAG .. " " .. i18n("attack.start") .. " class=" .. config.weapon_class .. " weapon=" .. tostring(M.weapon())) running = true local lastFire, lastLog = 0, 0 connection = RunService.Heartbeat:Connect(function() if _G.SP_BF_ATTACK_TOKEN ~= MODULE_TOKEN then M.stop() return end if not running then return end local now = tick() if now - lastFire < config.tick_interval then return end lastFire = now ensureAura() if not ensureWeaponEquipped() then return end local target, dist, targets = chooseTarget() if not target then if now - lastLog > 5 then lastLog = now print(TAG .. " " .. i18n("attack.no_target")) end return end if dist > getAttackSweepRange() then return end local ok, source = fireOnceToTarget(target, targets) if now - lastLog > 2 then lastLog = now print(TAG .. " " .. string.format(i18n("attack.target"), target.Name, math.floor(dist)) .. " | targets=" .. tostring(targets and #targets or 1) .. " | via=" .. source .. " ok=" .. tostring(ok)) end end) end function M.stop() if not running then return end running = false if connection then connection:Disconnect(); connection = nil end restoreOfficialHitboxes() print(TAG .. " " .. i18n("attack.stop")) end function M.setWeapon(name) config.weapon = name end function M.setAoePrimaryHits(n) MAX_TARGETS_PER_TICK = math.max(1, math.min(3, tonumber(n) or MAX_TARGETS_PER_TICK)) MAX_PRIMARY_HITS_PER_TICK = math.max(1, math.min(MAX_TARGETS_PER_TICK, tonumber(n) or MAX_PRIMARY_HITS_PER_TICK)) print(TAG .. " AOE primary hits=" .. tostring(MAX_PRIMARY_HITS_PER_TICK) .. " hitListMax=" .. tostring(MAX_TARGETS_PER_TICK)) end function M.setWeaponClass(class) if class ~= "melee" and class ~= "sword" and class ~= "gun" then warn(TAG .. " 未知武器类型: " .. tostring(class)) return end config.weapon_class = class print(TAG .. " 武器类型切换 → " .. class) if running then local desired = findWeaponByClass(class) if desired then equipTool(desired); print(TAG .. " " .. string.format(i18n("attack.weapon"), desired)) end end end function M.getWeaponClass() return config.weapon_class end function M.findWeaponByClass(class) return findWeaponByClass(class) end function M.setTargetProvider(fn) targetProvider = type(fn) == "function" and fn or nil end function M.setTargetFilter(fn) targetFilter = type(fn) == "function" and fn or nil end function M.setRange(n) config.range = math.max(1, tonumber(n) or cfg.ATTACK_RANGE) end function M.setTickInterval(n) config.tick_interval = math.max(0.03, tonumber(n) or config.tick_interval or 0.5) end function M.setSyncInterval(n) attackSyncPeriod = math.max(0.03, tonumber(n) or attackSyncPeriod or 0.5) end function M.setAttackIntervals(tickInterval, syncInterval) M.setTickInterval(tickInterval) M.setSyncInterval(syncInterval or tickInterval) print(TAG .. string.format(" 攻击间隔 tick=%.2fs sync=%.2fs", config.tick_interval, attackSyncPeriod)) end function M.getAttackIntervals() return config.tick_interval, attackSyncPeriod end function M.isRunning() return running end function M.ensureAura() return ensureAura() end function M.hasAura() return hasActiveAura() == true end function M.status() print(TAG .. " running=" .. tostring(running) .. " weapon=" .. tostring(M.weapon()) .. " aura=" .. tostring(hasActiveAura()) .. " range=" .. config.range .. " interval=" .. config.tick_interval .. " sync=" .. attackSyncPeriod .. " targetMax=" .. tostring(MAX_TARGETS_PER_TICK) .. " primaryMax=" .. tostring(MAX_PRIMARY_HITS_PER_TICK) .. " mode=official_hitbox+register_hit") end fm.register("Attack", function(target) return fireOnceToTarget(target) end) fm.register("EquipTool", equipTool) fm.register("GetEquippedTool", getEquippedTool) fm.register("ChooseTarget", chooseTarget) _G.bf_attack = M print(TAG .. " " .. i18n("loaded")) return M]] __src["./modules/combat_core"] = [[
local TAG = "[bf/combat]" local fm = _G.bf_fm local M = {} local attackOwner = nil local function isFiniteNumber(n) return type(n) == "number" and n == n and n > -math.huge and n < math.huge end local function isUsablePos(pos) return typeof(pos) == "Vector3" and isFiniteNumber(pos.X) and isFiniteNumber(pos.Y) and isFiniteNumber(pos.Z) and pos.Y > -1000 and pos.Y < 20000 and math.abs(pos.X) < 100000 and math.abs(pos.Z) < 100000 end function M.isAlive(mob) if not mob or not mob.Parent then return false end local hum = mob:FindFirstChildOfClass("Humanoid") local hrp = mob:FindFirstChild("HumanoidRootPart") return hum ~= nil and hum.Health > 0 and hrp ~= nil and isUsablePos(hrp.Position) end function M.matchesName(mob, wanted) if not mob or not wanted then return false end return tostring(mob.Name):lower():find(tostring(wanted):lower(), 1, true) ~= nil end function M.findFirst(predicate) local enemies = workspace:FindFirstChild("Enemies") if not enemies then return nil end for _, mob in ipairs(enemies:GetChildren()) do if M.isAlive(mob) and (not predicate or predicate(mob)) then return mob end end return nil end function M.findNearest(predicate, origin, maxDist) local enemies = workspace:FindFirstChild("Enemies") if not enemies then return nil, math.huge end if not isUsablePos(origin) then local hrp = fm and fm.getHRP and fm.getHRP() or nil origin = hrp and hrp.Position or nil end if not isUsablePos(origin) then return nil, math.huge end local best, bestDist = nil, math.huge for _, mob in ipairs(enemies:GetChildren()) do if M.isAlive(mob) and (not predicate or predicate(mob)) then local hrp = mob:FindFirstChild("HumanoidRootPart") local dist = hrp and (hrp.Position - origin).Magnitude or math.huge if dist < bestDist and (not maxDist or dist <= maxDist) then best, bestDist = mob, dist end end end return best, bestDist end function M.focus(owner, provider, filter, opts) opts = opts or {} if type(owner) ~= "string" or owner == "" then return false, "bad_owner" end if owner == "sea" and (opts.token == nil or opts.token ~= _G.SP_BF_SEAS_TOKEN) then return false, "stale_sea_flow" end if _G.bf_flow and _G.bf_flow.isLockedFor and _G.bf_flow.isLockedFor(owner) then return false, "flow_locked" end if attackOwner and attackOwner ~= owner and opts.force ~= true then local attackRunning = _G.bf_attack and _G.bf_attack.isRunning and _G.bf_attack.isRunning() or false if attackRunning then return false, attackOwner end attackOwner = nil end if not _G.bf_attack then return false, "missing_attack" end attackOwner = owner if _G.bf_attack.setTargetProvider then _G.bf_attack.setTargetProvider(provider) end if _G.bf_attack.setTargetFilter then _G.bf_attack.setTargetFilter(filter) end if _G.bf_attack.start and (opts.start ~= false) then pcall(function() _G.bf_attack.start() end) end return true end function M.stop(owner, force) if owner and attackOwner and attackOwner ~= owner and force ~= true then return false, attackOwner end if _G.bf_attack then if _G.bf_attack.stop then pcall(function() _G.bf_attack.stop() end) end if _G.bf_attack.setTargetProvider then pcall(function() _G.bf_attack.setTargetProvider(nil) end) end if _G.bf_attack.setTargetFilter then pcall(function() _G.bf_attack.setTargetFilter(nil) end) end end if not owner or attackOwner == owner or force == true then attackOwner = nil end return true end function M.owner() return attackOwner end function M.status() print(TAG .. " attackOwner=" .. tostring(attackOwner or "none")) end _G.bf_combat = M print(TAG .. " loaded") return M]] __src["./modules/get_quest"] = [[
local TAG = "[bf/quest]" local i18n = _G.bf_i18n local fm = _G.bf_fm local cfg = _G.bf_config local RunService = game:GetService("RunService") local M = {} local MODULE_TOKEN = {} _G.SP_BF_QUEST_TOKEN = MODULE_TOKEN local running = false local connection = nil local currentQuest = nil local serverProgress = { cur = 0, max = 0 } local INVOKE_TIMEOUT = 2.5 local function invokeWithTimeout(rf, ...) local args = { ... } local done, ok, res = false, false, nil task.spawn(function() ok, res = pcall(function() return rf:InvokeServer(unpack(args)) end) done = true end) local start = os.clock() while not done and os.clock() - start < INVOKE_TIMEOUT do task.wait() end if not done then return false, nil, "timeout" end return ok, res, nil end local function getBestQuestByLevel(lv) local best, bestLv, seaIdx, subIdx = nil, -1, nil, nil for si, sea in ipairs(cfg.SEA_GROUPS) do for sj, q in ipairs(sea.quests) do if q.lv <= lv and q.lv > bestLv then best, bestLv, seaIdx, subIdx = q, q.lv, si, sj end end end return best, seaIdx, subIdx end local QUEST_MOB_MAP = { ["Bandit"] = "BanditQuest1", ["Trainee"] = "MarineQuest", ["Monkey"] = "JungleQuest", ["Pirate"] = "BuggyQuest1", ["Desert Bandit"] = "DesertQuest", ["Snow Bandit"] = "SnowQuest", ["Gladiator"] = "ColosseumQuest", ["Sky Bandit"] = "SkyQuest", ["Fishman Warrior"] = "FishmanQuest", ["God's Guard"] = "FountainQuest", } local function identifyMobAndQuest(mobName) return QUEST_MOB_MAP[mobName] end local QUEST_TARGET_HINTS = { BanditQuest1 = { "Bandit" }, MarineQuest = { "Trainee" }, MarineQuest2 = { "Chief Petty Officer" }, JungleQuest = { "Monkey" }, BuggyQuest1 = { "Pirate" }, DesertQuest = { "Desert Bandit" }, SnowQuest = { "Snow Bandit" }, ColosseumQuest = { "Toga Warrior" }, MagmaQuest = { "Military Soldier" }, FishmanQuest = { "Fishman Warrior" }, SkyQuest = { "Sky Bandit" }, FountainQuest = { "Galley Pirate" }, } local function getQuestTier(tier) return math.max(1, tonumber(tier) or 1) end local function getQuestTargetHints(questName, tier) tier = getQuestTier(tier) for _, sea in ipairs(cfg.SEA_GROUPS or {}) do for _, q in ipairs(sea.quests or {}) do if q.n == questName and getQuestTier(q.tier) == tier then if type(q.mobs) == "table" and #q.mobs > 0 then return q.mobs end if type(q.mob) == "string" and q.mob ~= "" then return { q.mob } end end end end return QUEST_TARGET_HINTS[tostring(questName) .. ":" .. tostring(tier)] or QUEST_TARGET_HINTS[questName] end local function questTextMatches(questName, tier, text) local hints = getQuestTargetHints(questName, tier) if not hints then return true end local lowerText = tostring(text or ""):lower() for _, hint in ipairs(hints) do local h = tostring(hint or ""):lower() if lowerText:find(h, 1, true) or lowerText:find(h .. "s", 1, true) then return true end end return false end local function readServerQuestProgress() local lp = game.Players.LocalPlayer local main = lp.PlayerGui:FindFirstChild("Main") local quest = main and main:FindFirstChild("Quest") if not quest or not quest.Visible then return nil, nil end local function findProgressText(root) for _, c in ipairs(root:GetDescendants()) do if c:IsA("TextLabel") and c.Visible and c.Text then local cur, max = c.Text:match("%((%d+)/(%d+)%)") if cur and max then return c.Text end end end end local text = findProgressText(quest) if not text then return nil, nil end local cur, max = text:match("%((%d+)/(%d+)%)") if cur and max then return tonumber(cur), tonumber(max), text end return nil, nil, nil end local function fireStartQuest(questName, tier) local r = fm.getRemotes() if not r then return false end for _, name in ipairs({ "CommF_", "CommF" }) do local rf = r:FindFirstChild(name) if rf then local ok, res, err = invokeWithTimeout(rf, "StartQuest", questName, tier) if err == "timeout" then warn(TAG .. " " .. name .. " StartQuest 超时") end if not ok then warn(TAG .. " " .. name .. " StartQuest RPC 失败: " .. tostring(res)) end task.wait(0.6) local cur, max, text = readServerQuestProgress() if cur and max and max > 0 and questTextMatches(questName, tier, text) then print(TAG .. " ✓ StartQuest " .. questName .. " tier=" .. tier .. " 真接取成功 (UI 显示 " .. cur .. "/" .. max .. ")") return true end if cur and max and max > 0 then warn(TAG .. " StartQuest " .. questName .. " 后 UI 目标不匹配: " .. tostring(text)) end if ok then warn(TAG .. " " .. name .. " StartQuest 返回了但 UI 没有任务进度 — 视为未接到") end end end do local lp = game.Players.LocalPlayer local main = lp.PlayerGui:FindFirstChild("Main") local quest = main and main:FindFirstChild("Quest") if quest and quest.Visible then warn(TAG .. " StartQuest " .. questName .. " 后 Quest UI 可见但没有 (N/M) 进度") return false end end warn(TAG .. " StartQuest " .. questName .. " 未检测到 Quest UI 进度 - 可能远离 NPC 或服务端拒绝") return false end local function fireAbandonQuest() local r = fm.getRemotes() if not r then return false end for _, name in ipairs({ "CommF", "CommF_" }) do local rf = r:FindFirstChild(name) if rf then local ok = invokeWithTimeout(rf, "AbandonQuest") if ok then return true end end end return false end local function getBestQuestNPC() local r = fm.getRemotes() if not r then return nil end local rf = r:FindFirstChild("GetBestQuestNPC") if not rf then return nil end local ok, res, err = invokeWithTimeout(rf) if err == "timeout" then warn(TAG .. " GetBestQuestNPC 超时") end if not ok then return nil end return res end function M.start(questName, tier) if running then M.stop() end if not questName then warn(TAG .. " 缺 questName 参数") return end tier = tonumber(tier) or 1 currentQuest = { name = questName, tier = tier } print(TAG .. " " .. string.format(i18n("quest.start"), questName, tier)) fireStartQuest(questName, tier) running = true serverProgress = { cur = 0, max = 0 } local lastTick = 0 connection = RunService.Heartbeat:Connect(function() if _G.SP_BF_QUEST_TOKEN ~= MODULE_TOKEN then M.stop() return end if not running then return end local now = tick() if now - lastTick < 1.5 then return end lastTick = now local cur, max = readServerQuestProgress() if cur and max then if cur ~= serverProgress.cur or max ~= serverProgress.max then serverProgress = { cur = cur, max = max } print(TAG .. " " .. string.format(i18n("quest.progress"), questName, cur, max)) end if cur >= max and max > 0 then print(TAG .. " " .. i18n("quest.completed")) task.wait(0.5) fireStartQuest(currentQuest.name, currentQuest.tier) serverProgress = { cur = 0, max = 0 } end end end) end _G.SP_BF_CLEANUPS = _G.SP_BF_CLEANUPS or {} table.insert(_G.SP_BF_CLEANUPS, function() M.stop() end) function M.stop() if not running then return end running = false if connection then connection:Disconnect(); connection = nil end pcall(fireAbandonQuest) print(TAG .. " " .. i18n("quest.stop")) end function M.auto() if _G.bf_farm and _G.bf_farm.isRunning and _G.bf_farm.isRunning() then print(TAG .. " AutoFarm 正在运行, 自动接任务由 AutoFarm 接管") return end local lv = fm.getLevel() local q, si, sj = getBestQuestByLevel(lv) if not q then warn(TAG .. " " .. i18n("quest.no_quest") .. " lv=" .. lv) return end print(TAG .. " auto-pick: " .. q.n .. " tier=" .. tostring(q.tier or 1) .. " (lv=" .. q.lv .. " sea=" .. si .. ")") M.start(q.n, q.tier or 1) end function M.abandon() pcall(fireAbandonQuest) end function M.progress() return serverProgress.cur, serverProgress.max end function M.currentQuest() return currentQuest end function M.isRunning() return running end function M.status() print(TAG .. " running=" .. tostring(running) .. " quest=" .. (currentQuest and (currentQuest.name .. ":" .. currentQuest.tier) or "(none)") .. " progress=" .. serverProgress.cur .. "/" .. serverProgress.max) end fm.register("StartQuest", fireStartQuest) fm.register("AbandonQuest", fireAbandonQuest) fm.register("GetBestQuestNPC", getBestQuestNPC) fm.register("ReadQuestProgress", readServerQuestProgress) fm.register("IdentifyMobAndQuest", identifyMobAndQuest) fm.register("GetBestQuestByLevel", getBestQuestByLevel) _G.bf_quest = M print(TAG .. " " .. i18n("loaded")) return M]] __src["./modules/get_saber"] = [[
local TAG = "[bf/saber]" local i18n = _G.bf_i18n local fm = _G.bf_fm local M = {} local running = false local steps = { "TalkedSon", "KilledMobLeader", "GetCup", "FillCup", "UsedCup", "GetTorch", "UsedTorch", "KilledSaberExpert", } function M.start() if running then return end running = true print(TAG .. " " .. i18n("saber.start")) print(TAG .. " (NOTE: Saber 链需要逐步操作 + 击杀两个 Boss, 后续版本会扩展自动化)") for i, s in ipairs(steps) do print(TAG .. " step " .. i .. ": " .. s) end end function M.stop() if not running then return end running = false print(TAG .. " stopped") end function M.isRunning() return running end function M.status() print(TAG .. " saber: " .. (running and "running" or "idle")) end _G.bf_saber = M print(TAG .. " " .. i18n("loaded")) return M]] __src["./modules/reach_new_seas"] = [[
local TAG = "[bf/seas]" local i18n = _G.bf_i18n local fm = _G.bf_fm local Players = game:GetService("Players") local ReplicatedStorage = game:GetService("ReplicatedStorage") local okVim, VirtualInputManager = pcall(function() return game:GetService("VirtualInputManager") end) if not okVim then VirtualInputManager = nil end local M = {} local MODULE_TOKEN = {} local SEA1_PLACE_ID = 2753915549 local SEA2_PLACE_ID = 4442272183 local SEA2_PLACE_IDS = { [SEA2_PLACE_ID] = true, [79091703265657] = true, } local SEA3_PLACE_ID = 7449423635 local SEA3_PLACE_IDS = { [SEA3_PLACE_ID] = true, [100117331123089] = true, } local DETECTIVE_POS = Vector3.new(4852, 6, 719) local ICE_DOOR_POS = Vector3.new(1348, 37, -1326) local ICE_ROOM_POS = Vector3.new(1280, 28, -1380) local KING_RED_HEAD_POS = Vector3.new(-1926, 12, 1739) local BARTILO_POS = Vector3.new(-456, 73, 300) local SWAN_PIRATE_SPAWN_POS = Vector3.new(1058, 138, 1242) local JEREMY_SPAWN_POS = Vector3.new(2100, 449, 649) local DON_SWAN_ROOM_POS = Vector3.new(2293, 12, 663) local DON_SWAN_SPAWN_POS = Vector3.new(2289, 17, 662) local RIP_INDRA_SPAWN_POS = Vector3.new(-26952, 22, 329) local FALLBACK_COMBAT_CLEAR_POS = Vector3.new(-1441, 70, 6) local COMBAT_BLOCK_RETRY_TIMEOUT = 180 local PRE_BOSS_COMBAT_CLEAR_TIMEOUT = 12 local ICE_ADMIRAL_HOVER_HEIGHT = 45 local DON_SWAN_HOVER_HEIGHT = 45 local DON_SWAN_NO_DAMAGE_TIMEOUT = 45 local RIP_INDRA_HOVER_HEIGHT = 18 local RIP_INDRA_WAIT_TIMEOUT = 360 local RIP_INDRA_NO_DAMAGE_TIMEOUT = 45 local DON_SWAN_WAIT_TIMEOUT = 210 local SAFE_IDLE_HOVER_HEIGHT = 80 local SEA2_SAFE_HOVER_POS = Vector3.new(-385, 180, 297) local TREVOR_FRUIT_MIN_VALUE = 1000000 local TREVOR_RETRY_INTERVAL = 12 local BARTILO_TIMEOUT = 720 local STORY_MOB_HOVER_HEIGHT = 30 local BARTILO_PLATE_POSITIONS = { Vector3.new(-1850.493, 13.179, 1750.897), Vector3.new(-1858.873, 19.378, 1712.018), Vector3.new(-1803.943, 16.579, 1750.897), Vector3.new(-1858.558, 16.860, 1724.795), Vector3.new(-1869.542, 15.988, 1681.007), Vector3.new(-1800.098, 16.498, 1684.524), Vector3.new(-1819.263, 14.795, 1717.906), Vector3.new(-1813.518, 14.860, 1724.795), } local running = false local thread = nil local state = "idle" local lastLogAt = -math.huge local lastTravelResult = nil local bossReportedThisRun = false local donSwanConfirmedThisRun = false local runSeq = 0 local activeRunId = 0 local flyTo = nil local seaAfkOwned = false local lastTrevorWaitLogAt = -math.huge local lastDonSwanBlockLogAt = -math.huge local function runTag() if activeRunId and activeRunId > 0 then return "#" .. tostring(activeRunId) .. " " end return "" end local function store() _G.SP_BF_MODULES = _G.SP_BF_MODULES or {} if _G._snapshot then _G._snapshot.SP_BF_MODULES = true end return _G.SP_BF_MODULES end local function keepGlobalOnDevReload(name) if _G._snapshot and type(name) == "string" then _G._snapshot[name] = true end end local function importPendingUnlock() local s = store() if _G.SP_BF_PENDING_UNLOCK_SEA ~= nil then s._pending_unlock_sea = tonumber(_G.SP_BF_PENDING_UNLOCK_SEA) s._pending_unlock_reason = tostring(_G.SP_BF_PENDING_UNLOCK_REASON or "queued") s._pending_unlock_at = os.time() _G.SP_BF_PENDING_UNLOCK_SEA = nil _G.SP_BF_PENDING_UNLOCK_REASON = nil end return tonumber(s._pending_unlock_sea) end local function snapshotAutomationForUnlock() local s = store() if type(s._pending_unlock_restore) == "table" then return end s._pending_unlock_restore = { auto_farm = s.auto_farm == true, auto_attack = s.auto_attack == true, bring_mob = s.bring_mob == true, auto_quest = s.auto_quest == true, fly = s.fly == true, } end local function setPendingUnlock(targetSea, reason) local s = store() targetSea = tonumber(targetSea) or 3 s._pending_unlock_sea = targetSea s._pending_unlock_reason = tostring(reason or "start") s._pending_unlock_at = os.time() _G.SP_BF_PENDING_UNLOCK_SEA = targetSea _G.SP_BF_PENDING_UNLOCK_REASON = s._pending_unlock_reason keepGlobalOnDevReload("SP_BF_PENDING_UNLOCK_SEA") keepGlobalOnDevReload("SP_BF_PENDING_UNLOCK_REASON") snapshotAutomationForUnlock() return targetSea end local function clearPendingUnlock(targetSea) local s = store() if not targetSea or tonumber(s._pending_unlock_sea) == tonumber(targetSea) then s._pending_unlock_sea = nil s._pending_unlock_reason = nil s._pending_unlock_at = nil s._pending_unlock_queued_at = nil s._pending_unlock_queued_for = nil s._pending_unlock_queue_missing_at = nil s._pending_unlock_restore = nil _G.SP_BF_PENDING_UNLOCK_SEA = nil _G.SP_BF_PENDING_UNLOCK_REASON = nil end end local function getQueueOnTeleport() if type(queue_on_teleport) == "function" then return queue_on_teleport end if type(queueonteleport) == "function" then return queueonteleport end local synLib = rawget(_G, "syn") if type(synLib) == "table" and type(synLib.queue_on_teleport) == "function" then return synLib.queue_on_teleport end local fluxus = rawget(_G, "fluxus") if type(fluxus) == "table" and type(fluxus.queue_on_teleport) == "function" then return fluxus.queue_on_teleport end return nil end local function queuePendingReload(targetSea, reason) targetSea = setPendingUnlock(targetSea, reason or "teleport") local s = store() local now = os.time() if s._pending_unlock_queued_for == targetSea and s._pending_unlock_queued_at and now - s._pending_unlock_queued_at < 8 then return false end local queue = getQueueOnTeleport() if not queue then if not s._pending_unlock_queue_missing_at or now - s._pending_unlock_queue_missing_at >= 15 then s._pending_unlock_queue_missing_at = now print(TAG .. " " .. runTag() .. "当前执行器无 queue_on_teleport; 跨海后需要脚本自动执行或手动 reload 才能继续 pending Sea" .. tostring(targetSea)) end return false end local host = _G.env and _G.env.HOST if not host then print(TAG .. " " .. runTag() .. "未配置 _G.env.HOST, 跳过跨海自动继续注入(已脱敏)") return false end local snippet = table.concat({ "_G.LOAD_GAME=true", "_G.SP_BF_PENDING_UNLOCK_SEA=" .. tostring(targetSea), "_G.SP_BF_PENDING_UNLOCK_REASON=" .. string.format("%q", tostring(reason or "teleport_resume")), "loadstring(game:HttpGet(" .. string.format("%q", host .. "/devtools/devtools.lua") .. " .. '?t=' .. tostring(tick())))()", "if _G.dev and _G.dev.panel then pcall(function() _G.dev.panel('show_float') end) end", }, "; ") local ok, err = pcall(queue, snippet) if ok then s._pending_unlock_queued_for = targetSea s._pending_unlock_queued_at = now print(TAG .. " " .. runTag() .. "已注册跨海自动继续 Sea" .. tostring(targetSea) .. " 解锁流程") return true end print(TAG .. " " .. runTag() .. "注册跨海自动继续失败: " .. tostring(err)) return false end local function restoreAutomationAfterUnlock() local s = store() local flags = s._pending_unlock_restore if type(flags) ~= "table" then return end local resume = { auto_farm = flags.auto_farm == true, auto_attack = flags.auto_attack == true, bring_mob = flags.bring_mob == true, auto_quest = flags.auto_quest == true, fly = flags.fly == true, } task.spawn(function() task.wait(0.8) if resume.auto_farm and _G.bf_farm and _G.bf_farm.start then print(TAG .. " 第三海完成, 恢复 AutoFarm 到当前等级进度地图") pcall(function() _G.bf_farm.start() end) return end if resume.fly and _G.bf_fly and _G.bf_fly.on then pcall(function() _G.bf_fly.on() end) end if resume.auto_attack and _G.bf_attack and _G.bf_attack.start then pcall(function() _G.bf_attack.start() end) end if resume.bring_mob and _G.bf_bring and _G.bf_bring.start then pcall(function() _G.bf_bring.start() end) end if resume.auto_quest and _G.bf_quest and _G.bf_quest.auto then pcall(function() _G.bf_quest.auto() end) end end) end local function finishPendingUnlock(targetSea) restoreAutomationAfterUnlock() clearPendingUnlock(targetSea) end local function isCurrent() return _G.SP_BF_SEAS_TOKEN == MODULE_TOKEN end local function shouldRun() return running and isCurrent() end local function isSea1Place() return game.PlaceId == SEA1_PLACE_ID end local function isSea2Place() return SEA2_PLACE_IDS[game.PlaceId] == true end local function isSea3Place() return SEA3_PLACE_IDS[game.PlaceId] == true end local function setSeaFlowActive(active) _G.SP_BF_MODULES = _G.SP_BF_MODULES or {} _G.SP_BF_MODULES._sea_flow_active = active == true end local function log(msg, minGap) local now = os.clock() if not minGap or now - lastLogAt >= minGap then lastLogAt = now print(TAG .. " " .. runTag() .. tostring(msg)) end end local function valueText(v) if v == nil then return "nil" end if typeof(v) == "Instance" then return v.Name .. ":" .. v.ClassName end if type(v) == "table" then return "table" end return tostring(v) end local function isFiniteNumber(n) return type(n) == "number" and n == n and n > -math.huge and n < math.huge end local function isUsablePos(pos) return typeof(pos) == "Vector3" and isFiniteNumber(pos.X) and isFiniteNumber(pos.Y) and isFiniteNumber(pos.Z) and pos.Y > -1000 and pos.Y < 20000 and math.abs(pos.X) < 100000 and math.abs(pos.Z) < 100000 end local function horizontalDistance(a, b) if not isUsablePos(a) or not isUsablePos(b) then return math.huge end local dx = a.X - b.X local dz = a.Z - b.Z return math.sqrt(dx * dx + dz * dz) end local function getCombatClearPos() local origin = workspace:FindFirstChild("_WorldOrigin") local safeZones = origin and origin:FindFirstChild("SafeZones") local safePart = safeZones and safeZones:FindFirstChild("Safezone") if safePart and safePart:IsA("BasePart") and isUsablePos(safePart.Position) then return safePart.Position + Vector3.new(0, 6, 0) end return FALLBACK_COMBAT_CLEAR_POS end local function isSafeZoneVisible() local lp = Players.LocalPlayer local pg = lp and lp:FindFirstChild("PlayerGui") local main = pg and pg:FindFirstChild("Main") local hud = main and main:FindFirstChild("BottomHUDList") local safe = hud and hud:FindFirstChild("SafeZone") return safe and safe.Visible == true end local function getHRP() return fm.getHRP and fm.getHRP() or nil end local function getHumanoid() return fm.getHumanoid and fm.getHumanoid() or nil end local function getRemote(name) local remotes = fm.getRemotes and fm.getRemotes() or ReplicatedStorage:FindFirstChild("Remotes") return remotes and remotes:FindFirstChild(name) or nil end local function invoke(remoteName, ...) local remote = getRemote(remoteName) if not remote then return false, "missing:" .. tostring(remoteName) end local ok, res = pcall(function(...) return remote:InvokeServer(...) end, ...) if not ok then return false, res end return true, res end local function comm(...) local ok, res = invoke("CommF_", ...) if ok then return true, res, "CommF_" end ok, res = invoke("CommF", ...) if ok then return true, res, "CommF" end return false, res, "CommF/CommF_" end local function setState(nextState) if state ~= nextState then print(TAG .. " " .. runTag() .. "state: " .. tostring(state) .. " → " .. tostring(nextState)) state = nextState end end local function stopCombat() if _G.bf_combat and _G.bf_combat.stop then _G.bf_combat.stop("sea", true) elseif _G.bf_attack then if _G.bf_attack.setTargetProvider then pcall(function() _G.bf_attack.setTargetProvider(nil) end) end if _G.bf_attack.setTargetFilter then pcall(function() _G.bf_attack.setTargetFilter(nil) end) end if _G.bf_attack.stop then pcall(function() _G.bf_attack.stop() end) end end if _G.bf_bring and _G.bf_bring.stop then pcall(function() _G.bf_bring.stop() end) end end local function unequipTools() local hum = getHumanoid() if hum then pcall(function() hum:UnequipTools() end) end end local function stopConflictingLoops() if _G.bf_flow and _G.bf_flow.stopConflicts then _G.bf_flow.stopConflicts("sea") else if _G.bf_farm and _G.bf_farm.stop then pcall(function() _G.bf_farm.stop("sea_flow_fallback") end) end if _G.bf_quest and _G.bf_quest.stop then pcall(function() _G.bf_quest.stop() end) end stopCombat() end end local function ensureSeaAfk() task.spawn(function() for _ = 1, 30 do if not running then return end if _G.bf_extra and _G.bf_extra.afk_on then local wasRunning = _G.bf_extra.afk_running and _G.bf_extra.afk_running() or false if not wasRunning then seaAfkOwned = true end _G.bf_extra.afk_on() if _G.bf_extra.afk_cli