 hum:EquipTool(tool) end) end return tool.Parent == lp.Character end local function getIceDoor() local map = workspace:FindFirstChild("Map") local ice = map and map:FindFirstChild("Ice") local door = ice and ice:FindFirstChild("Door") if door and door:IsA("BasePart") then return door end if door then return door:FindFirstChildWhichIsA("BasePart", true) end return nil end local function isDoorOpen() local door = getIceDoor() if not door then return false end return door.CanCollide == false or door.Transparency >= 1 end local function touchDoor() local door = getIceDoor() local hrp = getHRP() if not door or not hrp then return false end local ok, res, remote = comm("UsedKey") print(TAG .. " UsedKey -> " .. tostring(remote) .. " " .. valueText(res)) pcall(function() hrp.CFrame = door.CFrame + Vector3.new(0, 3, 0) end) if type(firetouchinterest) == "function" then pcall(function() firetouchinterest(hrp, door, 0) end) task.wait(0.1) pcall(function() firetouchinterest(hrp, door, 1) end) end return true end local function looksLikeIceAdmiralName(name) local lower = tostring(name or ""):lower() return lower:find("ice admiral", 1, true) ~= nil and lower:find("awakened", 1, true) == nil end local function looksLikeRipIndraName(name) local lower = tostring(name or ""):lower() return lower:find("rip_indra", 1, true) ~= nil or (lower:find("rip", 1, true) ~= nil and lower:find("indra", 1, true) ~= nil) end local function looksLikeDonSwanName(name) local lower = tostring(name or ""):lower() return lower:find("don swan", 1, true) ~= nil end local function looksLikeSwanPirateName(name) return tostring(name or ""):lower():find("swan pirate", 1, true) ~= nil end local function looksLikeJeremyName(name) return tostring(name or ""):lower():find("jeremy", 1, true) ~= nil end local function findNearestEnemyByPredicate(predicate, origin) if _G.bf_combat and _G.bf_combat.findNearest then return _G.bf_combat.findNearest(predicate, origin) end local enemies = workspace:FindFirstChild("Enemies") local hrp = getHRP() origin = isUsablePos(origin) and origin or (hrp and hrp.Position or nil) if not enemies or not isUsablePos(origin) then return nil, math.huge end local best, bestDist = nil, math.huge for _, mob in ipairs(enemies:GetChildren()) do local hum = mob:FindFirstChildOfClass("Humanoid") local mhrp = mob:FindFirstChild("HumanoidRootPart") if hum and hum.Health > 0 and mhrp and isUsablePos(mhrp.Position) and predicate(mob) then local d = (mhrp.Position - origin).Magnitude if d < bestDist then best, bestDist = mob, d end end end return best, bestDist end local function findIceAdmiral() if _G.bf_combat and _G.bf_combat.findFirst then return _G.bf_combat.findFirst(function(mob) return looksLikeIceAdmiralName(mob.Name) end) end local enemies = workspace:FindFirstChild("Enemies") if not enemies then return nil end for _, mob in ipairs(enemies:GetChildren()) do local hum = mob:FindFirstChildOfClass("Humanoid") local hrp = mob:FindFirstChild("HumanoidRootPart") if looksLikeIceAdmiralName(mob.Name) and hum and hum.Health > 0 and hrp and isUsablePos(hrp.Position) then return mob end end return nil end local function findRipIndra() if _G.bf_combat and _G.bf_combat.findFirst then return _G.bf_combat.findFirst(function(mob) return looksLikeRipIndraName(mob.Name) end) end local enemies = workspace:FindFirstChild("Enemies") if not enemies then return nil end for _, mob in ipairs(enemies:GetChildren()) do local hum = mob:FindFirstChildOfClass("Humanoid") local hrp = mob:FindFirstChild("HumanoidRootPart") if looksLikeRipIndraName(mob.Name) and hum and hum.Health > 0 and hrp and isUsablePos(hrp.Position) then return mob end end return nil end local function findDonSwan() if _G.bf_combat and _G.bf_combat.findFirst then return _G.bf_combat.findFirst(function(mob) return looksLikeDonSwanName(mob.Name) end) end local enemies = workspace:FindFirstChild("Enemies") if not enemies then return nil end for _, mob in ipairs(enemies:GetChildren()) do local hum = mob:FindFirstChil