d end end local function fruitMeetsTrevor(fruit) if not fruit then return false end return (fruit.price or 0) >= TREVOR_FRUIT_MIN_VALUE end local function isPhysicalFruitTool(tool) if not tool or not tool:IsA("Tool") then return false end if tool:FindFirstChild("EatRemote") or tool:FindFirstChild("Fruit") then return true end if tool:FindFirstChild("Keep") and tool:FindFirstChild("Handle") then return true end if tostring(tool.Name):lower():find("fruit", 1, true) and tool:FindFirstChild("Handle") then return true end return false end local function findPhysicalTrevorFruit(catalog) local lp = Players.LocalPlayer local best = nil for _, parent in ipairs({ lp.Character, lp:FindFirstChild("Backpack") }) do if parent then for _, tool in ipairs(parent:GetChildren()) do if isPhysicalFruitTool(tool) then local fruit = matchFruitName(tool.Name, catalog) if fruitMeetsTrevor(fruit) then if not best or (fruit.price or 0) < (best.price or 0) then best = { tool = tool, name = fruit.name, price = fruit.price, rarity = fruit.rarity } end elseif fruit then log("跳过 Trevor 不合格实体果实: " .. tostring(tool.Name) .. " value=" .. tostring(fruit.price) .. " rarity=" .. tostring(fruit.rarity), 4) end end end end end return best end local function findStoredTrevorFruit(catalog) local ok, inventory = comm("getInventoryFruits") if not ok or type(inventory) ~= "table" then return nil end local names = {} collectStoredFruitNames(inventory, names) local best = nil for rawName in pairs(names) do local fruit = matchFruitName(rawName, catalog) or catalog[rawName] if fruitMeetsTrevor(fruit) then if not best or (fruit.price or 0) < (best.price or 0) then best = { name = fruit.name, rawName = rawName, price = fruit.price, rarity = fruit.rarity } end end end return best end local waitForPhysicalFruit local function cheapestTrevorFruit(catalog) local best = nil for _, fruit in pairs(catalog) do if fruitMeetsTrevor(fruit) and (fruit.price or 0) > 0 and fruit.offSale ~= true and fruit.onSale == true then if no