local TAG = "[bf/tool]" local i18n = _G.bf_i18n local fm = _G.bf_fm local cfg = _G.bf_config local M = {} local statAuto = { running = false, thread = nil, target = cfg.DEFAULT_AUTO_STAT or "Melee", index = 1 } local buyAuto = { running = false, thread = nil } local statAddBusy = false _G.__BF_AUTOSTAT_TOKEN = (_G.__BF_AUTOSTAT_TOKEN or 0) + 1 _G.__BF_AUTOBUY_TOKEN = (_G.__BF_AUTOBUY_TOKEN or 0) + 1 local lastStatBusyWarnAt = -math.huge local lastAutoBuyWaitAt = -math.huge local lastAutoBuyDeferAt = -math.huge local function nextAutoStatToken() _G.__BF_AUTOSTAT_TOKEN = (_G.__BF_AUTOSTAT_TOKEN or 0) + 1 return _G.__BF_AUTOSTAT_TOKEN end local function nextAutoBuyToken() _G.__BF_AUTOBUY_TOKEN = (_G.__BF_AUTOBUY_TOKEN or 0) + 1 return _G.__BF_AUTOBUY_TOKEN end local function isValidStatName(statName) for _, name in ipairs(cfg.STATS or {}) do if name == statName then return true end end return false end local function normalizeStatName(statName) if isValidStatName(statName) then return statName end return cfg.DEFAULT_AUTO_STAT or "Melee" end local function ensureModules() _G.SP_BF_MODULES = _G.SP_BF_MODULES or {} return _G.SP_BF_MODULES end local function defaultAutoStatSelection() local selected = {} for _, name in ipairs(cfg.DEFAULT_AUTO_STATS or { cfg.DEFAULT_AUTO_STAT or "Melee" }) do if isValidStatName(name) then selected[name] = true end end if not next(selected) then selected[normalizeStatName(nil)] = true end return selected end local function parseAutoStatSequence(text) if type(text) ~= "string" or text == "" then return nil end local selected = {} for name in string.gmatch(text, "([^|]+)") do if isValidStatName(name) then selected[name] = true end end return next(selected) and selected or nil end local function autoStatSequenceFromQueue(queue) queue = queue or {} return table.concat(queue, "|") end local function queueFromSelection(selected) local queue = {} for _, name in ipairs(cfg.STATS or {}) do if selected and selected[name] == true then table.insert(queue, name) end end return queue end local function writeAutoStatSelection(selected) local modules = ensureModules() local clean = {} for _, name in ipairs(cfg.STATS or {}) do clean[name] = selected and selected[name] == true or false end local queue = queueFromSelection(clean) modules.auto_stat_selected = clean modules.auto_stat_sequence = autoStatSequenceFromQueue(queue) modules.auto_stat_target = queue[1] return clean, queue end local function sanitizeAutoStatSelection() local modules = ensureModules() local raw = type(modules.auto_stat_selected) == "table" and modules.auto_stat_selected or parseAutoStatSequence(modules.auto_stat_sequence) if type(raw) ~= "table" then raw = {} if isValidStatName(modules.auto_stat_target) then raw[modules.auto_stat_target] = true else raw = defaultAutoStatSelection() end end local selected = writeAutoStatSelection(raw) return selected end local function autoStatQueue() local selected = sanitizeAutoStatSelection() return queueFromSelection(selected) end local function autoStatQueueText(queue) queue = queue or autoStatQueue() return #queue > 0 and table.concat(queue, " -> ") or "(none)" end local function nextAutoStatName() local queue = autoStatQueue() if #queue == 0 then return nil, queue end local modules = ensureModules() local index = math.floor(tonumber(modules.auto_stat_index or statAuto.index) or 1) if index < 1 or index > #queue then index = 1 end local name = queue[index] index = (index % #queue) + 1 statAuto.index = index modules.auto_stat_index = index statAuto.target = name modules.auto_stat_target = name return name, queue end local function statSnapshot() local snap = { points = fm.getStatPoints(), stats = {}, } for _, name in ipairs(cfg.STATS or {}) do snap.stats[name] = fm.getStatLevel(name) end return snap end local function printStatSnapshot(prefix) local s = statSnapshot() print(TAG .. string.format(" %s Points=%d | Melee=%d Sword=%d Gun=%d Defense=%d DF=%d", tostring(prefix or "stats"), s.points or 0, s.stats.Melee or 0, s.stats.Sword or 0, s.stats.Gun or 0, s.stats.Defense or 0, s.stats["Demon Fruit"] or 0)) return s end local function waitStatChange(statName, beforePoints, beforeLevel) local afterPoints, afterLevel = beforePoints, beforeLevel local deadline = os.clock() + 1.5 repeat task.wait(0.1) afterPoints = fm.getStatPoints() afterLevel = fm.getStatLevel(statName) if afterPoints < beforePoints or afterLevel > beforeLevel then break end until os.clock() >= deadline return afterPoints, afterLevel end local function invokeAddPoint(statName, amount, beforePoints, beforeLevel) local remotes = fm.getRemotes and fm.getRemotes() if not remotes then return false, "Remotes missing", nil, beforePoints, beforeLevel end local lastErr = "AddPoint invoke failed" for _, remoteName in ipairs({ "CommF_", "CommF" }) do local remote = remotes:FindFirstChild(remoteName) if remote then local ok, res = pcall(function() return remote:InvokeServer("AddPoint", statName, amount) end) if ok then local afterPoints, afterLevel = waitStatChange(statName, beforePoints, beforeLevel) if afterPoints < beforePoints or afterLevel > beforeLevel then return true, res, remoteName, afterPoints, afterLevel end lastErr = string.format("%s no stat change", remoteName) else lastErr = tostring(res) end end end return false, lastErr, nil, fm.getStatPoints(), fm.getStatLevel(statName) end local function isFiniteNumber(n) return type(n) == "number" and n == n and n > -math.huge and n < math.huge end local function isFiniteVector3(v) return typeof(v) == "Vector3" and isFiniteNumber(v.X) and isFiniteNumber(v.Y) and isFiniteNumber(v.Z) end local function resetCharacterMotion(reason) local hrp = fm.getHRP() local hum = fm.getHumanoid() if hum then pcall(function() hum.Sit = false end) pcall(function() hum.PlatformStand = false end) pcall(function() hum:ChangeState(Enum.HumanoidStateType.Running) end) end if not hrp then return false, "missing_hrp" end if not isFiniteVector3(hrp.Position) then warn(TAG .. " " .. tostring(reason or "角色") .. "坐标异常, 需要重生恢复") return false, "bad_position" end pcall(function() hrp.AssemblyLinearVelocity = Vector3.zero hrp.AssemblyAngularVelocity = Vector3.zero end) if not isFiniteVector3(hrp.AssemblyLinearVelocity) or not isFiniteVector3(hrp.AssemblyAngularVelocity) then warn(TAG .. " " .. tostring(reason or "角色") .. "速度异常, 已阻止恢复 AutoFarm") return false, "bad_velocity" end return true end local function isModuleRunning(mod) if not (mod and mod.isRunning) then return false end local ok, running = pcall(function() return mod.isRunning() end) return ok and running == true end local function isAutoFarmRunning() return isModuleRunning(_G.bf_farm) end local function shouldDeferBuyRemote() return isAutoFarmRunning() end local function noteBuyDeferred(reason, force) local now = os.clock() if force or now - lastAutoBuyDeferAt >= 20 then lastAutoBuyDeferAt = now print(TAG .. " 买武器已延后: AutoFarm 运行中, 不调用购买/查询 Remote" .. (reason and (" (" .. tostring(reason) .. ")") or "")) end end local function isCombatAutomationRunning() return isModuleRunning(_G.bf_farm) or isModuleRunning(_G.bf_attack) or isModuleRunning(_G.bf_bring) or isModuleRunning(_G.bf_fly) end local function warnStatBusy(message, force) local now = os.clock() if force or now - lastStatBusyWarnAt >= 8 then lastStatBusyWarnAt = now warn(TAG .. " " .. message) end end local function safeStop(mod, reason) if mod and mod.stop then pcall(function() mod.stop(reason) end) end end local function pauseForStatAdd() local ctx = { farm = isModuleRunning(_G.bf_farm), attack = isModuleRunning(_G.bf_attack), bring = isModuleRunning(_G.bf_bring), fly = isModuleRunning(_G.bf_fly), } if ctx.farm or ctx.attack or ctx.bring or ctx.fly then print(TAG .. " 加点前暂停挂机/移动, 防止角色物理状态污染") end if ctx.farm and _G.bf_farm and _G.bf_farm.pause then local ok, paused = pcall(function() return _G.bf_farm.pause("stat_add") end) ctx.farmPaused = ok and paused == true end if ctx.attack then safeStop(_G.bf_attack, "stat_add") end if ctx.bring then safeStop(_G.bf_bring, "stat_add") end if ctx.farm and not ctx.farmPaused then safeStop(_G.bf_farm, "stat_add") end if ctx.fly and _G.bf_fly and _G.bf_fly.stop then pcall(function() _G.bf_fly.stop() end) end ctx.physicsOk = resetCharacterMotion("加点前") == true task.wait(0.2) return ctx end local function resumeAfterStatAdd(ctx) local ok = resetCharacterMotion("加点后") if not ok then return end task.wait(0.2) if ctx and ctx.farm and ctx.farmPaused and _G.bf_farm and _G.bf_farm.resume then print(TAG .. " 加点后恢复 AutoFarm 状态") pcall(function() _G.bf_farm.resume("stat_add") end) return end if ctx and ctx.farm and _G.bf_farm and _G.bf_farm.start then print(TAG .. " 加点后恢复 AutoFarm") pcall(function() _G.bf_farm.start() end) return end if ctx and ctx.fly and _G.bf_fly and _G.bf_fly.on then pcall(function() _G.bf_fly.on() end) end if ctx and ctx.attack and _G.bf_attack and _G.bf_attack.start then pcall(function() _G.bf_attack.start() end) end if ctx and ctx.bring and _G.bf_bring and _G.bf_bring.start then pcall(function() _G.bf_bring.start() end) end end local function searchForItemInInventory(itemName) local lp = game.Players.LocalPlayer local bp = lp:FindFirstChild("Backpack") local char = lp.Character if bp then local t = bp:FindFirstChild(itemName) if t then return t, "backpack" end end if char then local t = char:FindFirstChild(itemName) if t then return t, "equipped" end end return nil, nil end local function searchForTool(itemName) local t = searchForItemInInventory(itemName) return t end local function equipTool(name) local f = _G.bf_fm local hum = f.getHumanoid() if not hum then return false end local cur = (game.Players.LocalPlayer.Character or {}):FindFirstChildOfClass("Tool") if cur and cur.Name == name then return true end local item = searchForItemInInventory(name) if not item or not item:IsA("Tool") then return false end pcall(function() hum:EquipTool(item) end) return true end function M.equip(name) if equipTool(name) then print(TAG .. " " .. string.format(i18n("tool.equip"), name)) return true else warn(TAG .. " " .. string.format(i18n("tool.no_inv"), name)) return false end end local function findWeaponDef(weaponName) for _, w in ipairs(cfg.WEAPONS or {}) do if w.name == weaponName then return w end end return nil end local function currencySnapshot() return { beli = fm.getBeli(), fragments = fm.getFragments(), } end local function moneySpent(before, after) if not before or not after then return false end return (tonumber(after.beli) or 0) < (tonumber(before.beli) or 0) or (tonumber(after.fragments) or 0) < (tonumber(before.fragments) or 0) end local function remoteInvokeRaw(remoteName, ...) local remotes = fm.getRemotes and fm.getRemotes() local remote = remotes and remotes:FindFirstChild(remoteName) if not remote then return false, "missing:" .. tostring(remoteName) end local ok, res = pcall(function(...) return remote:InvokeServer(...) end, ...) if not ok then return false, res end return true, res end local unpackArgs = table.unpack or unpack local TYPE_LABELS = { melee = "格斗", sword = "剑", gun = "枪", } local function weaponType(def) return tostring(def and def.type or "melee") end local function weaponTypeLabel(defOrType) local t = type(defOrType) == "table" and weaponType(defOrType) or tostring(defOrType or "melee") return TYPE_LABELS[t] or t end local function isValidBuyType(typeName) typeName = tostring(typeName or "") for _, t in ipairs(cfg.WEAPON_TYPES or { "melee", "sword", "gun" }) do if t == typeName then return true end end return false end local function defaultAutoBuyTypes() local selected = {} for _, t in ipairs(cfg.WEAPON_TYPES or { "melee", "sword", "gun" }) do selected[t] = cfg.DEFAULT_AUTO_BUY_TYPES and cfg.DEFAULT_AUTO_BUY_TYPES[t] == true or t == "melee" end return selected end local function sanitizeAutoBuyTypes() local modules = ensureModules() local raw = type(modules.auto_buy_types) == "table" and modules.auto_buy_types or defaultAutoBuyTypes() local clean = {} local any = false for _, t in ipairs(cfg.WEAPON_TYPES or { "melee", "sword", "gun" }) do clean[t] = raw[t] == true any = any or clean[t] end if not any then clean.melee = true end modules.auto_buy_types = clean return clean end local function selectedBuyTypesText(selected) selected = selected or sanitizeAutoBuyTypes() local parts = {} for _, t in ipairs(cfg.WEAPON_TYPES or { "melee", "sword", "gun" }) do if selected[t] == true then table.insert(parts, weaponTypeLabel(t)) end end return #parts > 0 and table.concat(parts, "/") or "无" end local function buyArgsFor(def) local args = { def.buy_cmd } for _, arg in ipairs(def.buy_args or {}) do table.insert(args, arg) end return args end local function invokeBuy(remoteName, def) local args = buyArgsFor(def) return remoteInvokeRaw(remoteName, unpackArgs(args)) end local function valueText(v) if v == nil then return "nil" end if typeof(v) == "Instance" then return v.Name .. ":" .. v.ClassName end return tostring(v) end local function responseLooksPositive(res) if res == true or res == 1 then return true end if type(res) == "string" then local s = string.lower(res) return s:find("bought", 1, true) or s:find("success", 1, true) or s:find("equipped", 1, true) or s:find("already", 1, true) end return false end local function weaponState(weaponName) local def = findWeaponDef(weaponName) if def and not def.buy_cmd then local item, localWhere = searchForItemInInventory(weaponName) return { localItem = item, localWhere = localWhere or "default", searchItemOk = true, searchItem = "default", searchToolOk = true, searchTool = "default", owned = true, } end local item, localWhere = searchForItemInInventory(weaponName) if shouldDeferBuyRemote() then return { localItem = item, localWhere = localWhere, searchItemOk = false, searchItem = "skipped_autofarm", searchToolOk = false, searchTool = "skipped_autofarm", owned = item ~= nil, remoteSkipped = true, } end local searchItemOk, searchItem = remoteInvokeRaw("CommF_", "SearchForItemInInventory", weaponName) local searchToolOk, searchTool = remoteInvokeRaw("CommF_", "SearchForTool", weaponName) local owned = item ~= nil or responseLooksPositive(searchItem) or responseLooksPositive(searchTool) return { localItem = item, localWhere = localWhere, searchItemOk = searchItemOk, searchItem = searchItem, searchToolOk = searchToolOk, searchTool = searchTool, owned = owned, } end local function priceText(def) local parts = {} if (tonumber(def.cost) or 0) > 0 then table.insert(parts, "$" .. tostring(def.cost)) end if (tonumber(def.fragments) or 0) > 0 then table.insert(parts, tostring(def.fragments) .. " fragments") end return #parts > 0 and table.concat(parts, " + ") or "server-priced" end local function compactNumber(n) n = tonumber(n) or 0 if n >= 1000000 then local v = math.floor(n / 100000 + 0.5) / 10 return tostring(v):gsub("%.0$", "") .. "m" end if n >= 1000 then return tostring(math.floor(n / 1000 + 0.5)) .. "k" end return tostring(n) end local function shortPriceText(def) local parts = {} if (tonumber(def.cost) or 0) > 0 then table.insert(parts, "$" .. compactNumber(def.cost)) end if (tonumber(def.fragments) or 0) > 0 then table.insert(parts, compactNumber(def.fragments) .. "F") end return #parts > 0 and table.concat(parts, "+") or "default" end local function budgetHint(def) local money = currencySnapshot() local okBeli = (tonumber(def.cost) or 0) <= 0 or money.beli >= def.cost local okFrag = (tonumber(def.fragments) or 0) <= 0 or money.fragments >= def.fragments if okBeli and okFrag then return "ok" end return string.format("low($%d/%s, frag=%d/%s)", money.beli or 0, tostring(def.cost or 0), money.fragments or 0, tostring(def.fragments or 0)) end local function canAffordWeapon(def, money) money = money or currencySnapshot() return ((tonumber(def.cost) or 0) <= 0 or (tonumber(money.beli) or 0) >= (tonumber(def.cost) or 0)) and ((tonumber(def.fragments) or 0) <= 0 or (tonumber(money.fragments) or 0) >= (tonumber(def.fragments) or 0)) end local function weaponCostScore(def) return (tonumber(def.cost) or 0) + (tonumber(def.fragments) or 0) * 1000 end local function sortedBuyWeapons(selectedTypes) selectedTypes = selectedTypes or sanitizeAutoBuyTypes() local rows = {} for _, w in ipairs(cfg.WEAPONS or {}) do if w.buy_cmd and selectedTypes[weaponType(w)] == true then table.insert(rows, w) end end table.sort(rows, function(a, b) local sa, sb = weaponCostScore(a), weaponCostScore(b) if weaponType(a) ~= weaponType(b) and sa == sb then return weaponType(a) < weaponType(b) end if sa == sb then return tostring(a.name) < tostring(b.name) end return sa < sb end) return rows end local function nextAutoBuyCandidate() local money = currencySnapshot() local selectedTypes = sanitizeAutoBuyTypes() local firstMissing = nil for _, w in ipairs(sortedBuyWeapons(selectedTypes)) do if not weaponState(w.name).owned then firstMissing = firstMissing or w if canAffordWeapon(w, money) then return w, nil, money end end end return nil, firstMissing, money end function M.buy(weaponName) local def = findWeaponDef(weaponName) if not def then warn(TAG .. " 未知武器: " .. weaponName); return false end if not def.buy_cmd then print(TAG .. " " .. tostring(weaponName) .. " 是默认武器, 无需购买") return false end if shouldDeferBuyRemote() then noteBuyDeferred("buy " .. tostring(weaponName), true) return false end local beforeMoney = currencySnapshot() local beforeState = weaponState(weaponName) if beforeState.owned then print(TAG .. " 已拥有/可用: " .. tostring(weaponName)) return true end local attempts = {} for _, remoteName in ipairs({ "CommF_", "CommF" }) do local ok, res = invokeBuy(remoteName, def) table.insert(attempts, remoteName .. "=" .. valueText(res)) task.wait(0.25) local afterMoney = currencySnapshot() local afterState = weaponState(weaponName) if afterState.owned or moneySpent(beforeMoney, afterMoney) or responseLooksPositive(res) then print(TAG .. string.format(" 购买确认: %s via=%s res=%s money %d/%d → %d/%d", weaponName, remoteName, valueText(res), beforeMoney.beli or 0, beforeMoney.fragments or 0, afterMoney.beli or 0, afterMoney.fragments or 0)) return true end end warn(TAG .. string.format(" 购买未确认: %s price=%s budget=%s attempts={%s}", weaponName, priceText(def), budgetHint(def), table.concat(attempts, ", "))) return false end function M.buyInfo(weaponName) local def = findWeaponDef(weaponName) if not def then return nil end local money = currencySnapshot() local state = weaponState(weaponName) return { name = def.name, price = priceText(def), short_price = shortPriceText(def), type = weaponType(def), type_label = weaponTypeLabel(def), owned = state.owned, affordable = canAffordWeapon(def, money), buy_cmd = def.buy_cmd, remote_skipped = state.remoteSkipped == true, beli = money.beli or 0, fragments = money.fragments or 0, cost = tonumber(def.cost) or 0, cost_fragments = tonumber(def.fragments) or 0, } end function M.buyButtonText(weaponName) local info = M.buyInfo(weaponName) if not info then return "未知 " .. tostring(weaponName) end if info.remote_skipped then return string.format("挂机中 [%s] %s %s", info.type_label, info.name, info.short_price) end local state = info.owned and "已拥有" or (info.affordable and "可买" or "差钱") return string.format("%s [%s] %s %s", state, info.type_label, info.name, info.short_price) end function M.buyPlanText() if shouldDeferBuyRemote() then return "自动购买延后: AutoFarm 运行中, 为避免打断刷怪不发购买 Remote" end local candidate, waitFor, money = nextAutoBuyCandidate() local selectedText = selectedBuyTypesText() if candidate then return string.format("自动下一项(%s): [%s] %s %s | 当前 $%d / %dF", selectedText, weaponTypeLabel(candidate), candidate.name, shortPriceText(candidate), money.beli or 0, money.fragments or 0) end if waitFor then return string.format("自动等待(%s): [%s] %s %s | 当前 $%d / %dF", selectedText, weaponTypeLabel(waitFor), waitFor.name, shortPriceText(waitFor), money.beli or 0, money.fragments or 0) end return string.format("自动购买(%s): 配置内已买完 | 当前 $%d / %dF", selectedText, money.beli or 0, money.fragments or 0) end function M.buyManual(weaponName) if shouldDeferBuyRemote() then noteBuyDeferred("manual " .. tostring(weaponName), true) return false end local info = M.buyInfo(weaponName) if not info then warn(TAG .. " 未知武器: " .. tostring(weaponName)); return false end if not info.buy_cmd then print(TAG .. " " .. tostring(weaponName) .. " 是默认武器, 无需购买") return false end if info.owned then print(TAG .. " 已拥有/可用: " .. tostring(weaponName)) return true end if not info.affordable then warn(TAG .. string.format(" 暂不可买: %s price=%s have=$%d/%dF", tostring(weaponName), info.price, info.beli, info.fragments)) return false end return M.buy(weaponName) end local function nameListText(list) return #list > 0 and table.concat(list, ", ") or "(none)" end function M.buyAllAffordable() if shouldDeferBuyRemote() then noteBuyDeferred("buy_all", true) return {} end local bought, failed, skipped = {}, {}, {} local money = currencySnapshot() for _, w in ipairs(sortedBuyWeapons(sanitizeAutoBuyTypes())) do if weaponState(w.name).owned then table.insert(skipped, w.name .. ":owned") elseif canAffordWeapon(w, money) then local ok = M.buy(w.name) if ok then table.insert(bought, w.name) money = currencySnapshot() else table.insert(failed, w.name) end task.wait(0.35) else table.insert(skipped, w.name .. ":money") end end print(TAG .. " 手动购买汇总 bought=" .. nameListText(bought) .. " skipped=" .. nameListText(skipped) .. " failed=" .. nameListText(failed)) return bought end function M.buyStatus() local money = currencySnapshot() print(TAG .. string.format(" 购买状态: Beli=%d Fragments=%d autoTypes=%s", money.beli or 0, money.fragments or 0, selectedBuyTypesText())) for _, w in ipairs(cfg.WEAPONS or {}) do local state = weaponState(w.name) print(TAG .. string.format(" weapon=[%s] %s cmd=%s price=%s budget=%s owned=%s local=%s searchItem=%s searchTool=%s", weaponTypeLabel(w), tostring(w.name), tostring(w.buy_cmd), priceText(w), w.buy_cmd and budgetHint(w) or "default", tostring(state.owned), state.localItem and (tostring(state.localWhere) .. ":