local TAG = "[bf/tween]" local i18n = _G.bf_i18n local fm = _G.bf_fm local cfg = _G.bf_config local TS = game:GetService("TweenService") local TPS = game:GetService("TeleportService") local HS = game:GetService("HttpService") local RunService = game:GetService("RunService") local M = {} local currentTween = nil local flyConnection = nil local flyTarget = nil local SEA_PLACE_IDS = { [1] = 2753915549, [2] = 4442272183, [3] = 7449423635, } local SEA_TRAVEL_COMMANDS = { [1] = "TravelMain", [2] = "TravelDressrosa", [3] = "TravelZou", } local function valueText(v) if v == nil then return "nil" end if typeof(v) == "Instance" then return v.Name .. ":" .. v.ClassName end return tostring(v) end local function currentSea() local tag = cfg and cfg.SEA_BOUNDS and cfg.SEA_BOUNDS[game.PlaceId] or nil if type(tag) == "string" then local idx = tonumber(tag:match("^sea(%d+)$")) if idx then return idx end end for seaIdx, placeId in pairs(SEA_PLACE_IDS) do if game.PlaceId == placeId then return seaIdx end end return nil end local function invokeRemote(remoteName, ...) local remotes = fm.getRemotes and fm.getRemotes() local remote = remotes and remotes:FindFirstChild(remoteName) if not remote then return false, "missing:" .. tostring(remoteName) end local ok, res = pcall(function(...) return remote:InvokeServer(...) end, ...) if not ok then return false, res end return true, res end local function looksLikeTravelBlocked(res) if type(res) ~= "string" then return false end local s = string.lower(res) return s:find("level", 1, true) or s:find("not", 1, true) or s:find("can't", 1, true) or s:find("cannot", 1, true) or s:find("unlock", 1, true) or s:find("complete", 1, true) or s:find("quest", 1, true) end local function automationFlagSnapshot() local modules = _G.SP_BF_MODULES or {} return { auto_farm = modules.auto_farm == true, auto_attack = modules.auto_attack == true, bring_mob = modules.bring_mob == true, auto_quest = modules.auto_quest == true, fly = modules.fly == true, } end local function restoreAutomationFlags(flags) if type(flags) ~= "table" then return end _G.SP_BF_MODULES = _G.SP_BF_MODULES or {} for key, value in pairs(flags) do _G.SP_BF_MODULES[key] = value == true end end local function resumeAutomation(flags) restoreAutomationFlags(flags) if type(flags) ~= "table" then return end local flowOwner = _G.bf_flow and _G.bf_flow.owner and _G.bf_flow.owner() or nil if flowOwner == "sea" or (_G.SP_BF_MODULES and _G.SP_BF_MODULES._sea_flow_active == true) then print(TAG .. " 流程锁占用中, 跳过自动恢复") return end if flags.auto_farm and _G.bf_farm and _G.bf_farm.start then pcall(function() _G.bf_farm.start() end) return end if flags.auto_attack and _G.bf_attack and _G.bf_attack.start then pcall(function() _G.bf_attack.start() end) end if flags.bring_mob and _G.bf_bring and _G.bf_bring.start then pcall(function() _G.bf_bring.start(cfg.BRING_DEFAULT_DISTANCE, nil, true) end) end if flags.auto_quest and _G.bf_quest and _G.bf_quest.auto then pcall(function() _G.bf_quest.auto() end) end if flags.fly and _G.bf_fly and _G.bf_fly.on then pcall(function() _G.bf_fly.on() end) end end local function stopForSeaTravel(targetSea) local flags = automationFlagSnapshot() _G.SP_BF_MODULES = _G.SP_BF_MODULES or {} _G.SP_BF_MODULES._manual_sea_travel_target = targetSea _G.SP_BF_MODULES._manual_sea_travel_at = os.time() _G.SP_BF_MODULES._manual_sea_travel_restore = flags for _, mod in ipairs({ _G.bf_farm, _G.bf_bring, _G.bf_attack, _G.bf_quest }) do if mod and mod.stop then pcall(function() mod.stop() end) end end if _G.bf_fly and _G.bf_fly.clearAutoTarget then pcall(function() _G.bf_fly.clearAutoTarget() end) end M.cancel() M.stopHover() return flags end local function tweenCharacterToPosition(targetPos, speed) local hrp = fm.getHRP() if not hrp then return false end if currentTween then pcall(function() currentTween:Cancel() end); currentTween = nil end speed = speed or 350 local startPos = hrp.Position local dist = (targetPos - startPos).Magnitude local time = math.max(0.1