," .. math.floor(center.Y) .. "," .. math.floor(center.Z)) if _G.SP_BF_DEV_VERBOSE ~= false then task.spawn(function() local hrp = fm.getHRP() if not hrp then return end local p0 = hrp.Position task.wait(2) local p1 = fm.getHRP() and fm.getHRP().Position or p0 local moved = (p1 - p0).Magnitude local distRemaining = (center - p1).Magnitude print(TAG .. " [dev] go(" .. islandName .. ") 2s 后: moved=" .. math.floor(moved) .. "m  剩余=" .. math.floor(distRemaining) .. "m") end) end if useFly then return M.flyTo(center + Vector3.new(0, 30, 0)) else return tweenCharacterToPosition(center, 350) end end _G.bf = _G.bf or {} _G.bf.go = function(name) return M.go(name, true) end function M.bypass(targetCFrame) print(TAG .. " " .. i18n("tween.bypass")) local hrp = fm.getHRP() if not hrp then return false end local mid = CFrame.new(targetCFrame.Position + Vector3.new(0, 5000, 0)) pcall(function() hrp.CFrame = mid end) task.wait(0.1) pcall(function() hrp.CFrame = targetCFrame end) return true end local function listServers(placeId, cursor) local url = "https://games.roblox.com/v1/games/" .. placeId .. "/servers/Public?sortOrder=Asc&limit=100" if cursor and cursor ~= "" then url = url .. "&cursor=" .. cursor end local ok, res = pcall(function() return HS:JSONDecode(game:HttpGet(url)) end) return ok and res or nil end local function pickServer(placeId, maxPlayers) local placeId = placeId or game.PlaceId maxPlayers = maxPlayers or 10 local cursor = "" for _ = 1, 5 do local data = listServers(placeId, cursor) if not data or not data.data then break end local best = nil for _, srv in ipairs(data.data) do if srv.id ~= game.JobId and srv.playing < srv.maxPlayers and srv.playing <= maxPlayers then if not best or srv.playing < best.playing then best = srv end end end if best then return best.id, best.playing end cursor = data.nextPageCursor or "" if cursor == "" then break end end return nil end function M.hop(maxPlayers) local jobId, playing = pickServer(game.PlaceId, maxPlayers or 8) if not jobId then warn(TAG .. " " .. i18n("tween.no_server")) return false end print(TAG .. " " .. string.format(i18n("tween.hop"), playing or 0)) pcall(function() TPS:TeleportToPlaceInstance(game.PlaceId, jobId, game.Players.LocalPlayer) end) return true end function M.travelToSea(seaIdx) seaIdx = tonumber(seaIdx) local pid = SEA_PLACE_IDS[seaIdx] if not pid then return false end if currentSea() == seaIdx then print(TAG .. " 已在第 " .. tostring(seaIdx) .. " 海") return true end local previousAutomation = stopForSeaTravel(seaIdx) local cmd = SEA_TRAVEL_COMMANDS[seaIdx] if cmd then for _, remoteName in ipairs({ "CommF_", "CommF" }) do local ok, res = invokeRemote(remoteName, cmd) if ok then print(TAG .. string.format(" 切换到第%d海: %s.%s -> %s", seaIdx, remoteName, cmd, valueText(res))) if looksLikeTravelBlocked(res) then resumeAutomation(previousAutomation) return false end return true end end end print(TAG .. string.format(" 切换到第%d海: Remote 不可用, 使用 Teleport 兜底", seaIdx)) local ok, err = pcall(function() TPS:Teleport(pid, game.Players.LocalPlayer) end) if not ok then resumeAutomation(previousAutomation) warn(TAG .. " Teleport 失败: " .. tostring(err)) return false end return true end function M.to(cf, useFly) if useFly then return M.flyTo(cf.Position) end return tweenCharacterToPosition(cf.Position, 350) end function M.status() print(TAG .. " tween=" .. (currentTween and "active" or "idle") .. " hover=" .. (flyConnection and "active" or "idle")) end function M.stop() M.cancel() M.stopHover() end fm.register("tweenCharacterToPosition", tweenCharacterToPosition) fm.register("bypassTeleport", M.bypass) fm.register("TeleportBetweenServers", M.hop) fm.register("TeleportToSea", M.travelToSea) _G.bf_tween = M print(TAG .. " " .. i18n("loaded")) return M]] __src["./modules/fly"] = [[
local TAG = "[bf/fly]" local i18n = _G.bf_i18n local fm = _G.bf_fm local RunService = game:GetService("RunService") local M = {} local MODULE_TOKEN = {} _G.SP_BF_FLY_TOKEN = MODULE_TOKEN local running = false local heartConn = nil local charConn = nil local origState = { autoRotate = nil, walkSpeed = nil, jumpPower = nil, platformStand = nil } local origCollide = {} local bodyPos = nil local bodyGyro = nil local bodyVel = nil local config = { height = 40, autoSpeed = 100, } local MIN_SAFE_HEIGHT = 20 local PROTECTED_UNOWNED_TARGETS = { Vector3.new(1266, 26, -1400), Vector3.new(1280, 28, -1380), Vector3.new(1348, 37, -1326), Vector3.new(4852, 6, 719), } local function isFiniteNumber(n) return type(n) == "number" and n == n and n > -math.huge and n < math.huge end local function isUsablePos(pos) if typeof(pos) ~= "Vector3" then return false end if not isFiniteNumber(pos.X) or not isFiniteNumber(pos.Y) or not isFiniteNumber(pos.Z) then return false end if pos.Y < -1000 or pos.Y > 20000 then return false end if math.abs(pos.X) > 100000 or math.abs(pos.Z) > 100000 then return false end return true end local function isFiniteVector3(v) return typeof(v) == "Vector3" and isFiniteNumber(v.X) and isFiniteNumber(v.Y) and isFiniteNumber(v.Z) end local function isProtectedUnownedTarget(pos) if not isUsablePos(pos) then return false end for _, target in ipairs(PROTECTED_UNOWNED_TARGETS) do local dx = pos.X - target.X local dz = pos.Z - target.Z if math.sqrt(dx * dx + dz * dz) <= 120 then return true end end return false end local function isFiniteCFrame(cf) if typeof(cf) ~= "CFrame" then return false end local values = { cf:GetComponents() } for _, n in ipairs(values) do if not isFiniteNumber(n) then return false end end return true end local lastPhysicsWarnAt = -math.huge local lastBlockedTargetLogAt = -math.huge local function warnPhysics(msg) local now = os.clock() if now - lastPhysicsWarnAt >= 2 then lastPhysicsWarnAt = now warn(TAG .. " " .. msg) end end local function logBlockedTarget(reason, pos) local now = os.clock() if now - lastBlockedTargetLogAt < 2 then return end lastBlockedTargetLogAt = now print(TAG .. " " .. tostring(reason) .. ": " .. tostring(math.floor(pos.X)) .. "," .. tostring(math.floor(pos.Y)) .. "," .. tostring(math.floor(pos.Z))) end local function rejectStaleTarget(reason, pos) logBlockedTarget(reason, pos) error(TAG .. " " .. tostring(reason), 2) end local function isSeaControlActive() return _G.SP_BF_SEAS_TOKEN ~= nil or (_G.SP_BF_MODULES and _G.SP_BF_MODULES._sea_flow_active == true) end local function isCurrentSeaControl(opts) return opts and opts.owner == "sea" and opts.token ~= nil and opts.token == _G.SP_BF_SEAS_TOKEN end local function shouldBlockFlyControl(opts) return isSeaControlActive() and not isCurrentSeaControl(opts) end local lastBlockedControlLogAt = -math.huge local function logBlockedControl(reason) local now = os.clock() if now - lastBlockedControlLogAt < 2 then return end lastBlockedControlLogAt = now print(TAG .. " " .. tostring(reason)) end local function safeRotation(hrp) if hrp and isFiniteCFrame(hrp.CFrame) then return hrp.CFrame - hrp.CFrame.Position end return CFrame.new() end local function sanitizeHRP(hrp) if not hrp then return false, "missing_hrp" end if not isUsablePos(hrp.Position) then return false, "bad_position" end local fixed = false if not isFiniteVector3(hrp.AssemblyLinearVelocity) then fixed = true pcall(function() hrp.AssemblyLinearVelocity = Vector3.zero end) end if not isFiniteVector3(hrp.AssemblyAngularVelocity) then fixed = true pcall(function() hrp.AssemblyAngularVelocity = Vector3.zero end) end if fixed then warnPhysics("HRP 速度出现 NaN/Inf, 已清零并重新校验") end if not isFiniteVector3(hrp.AssemblyLinearVelocity) then return false, "bad_linear_velocity" end if not isFiniteVector3(hrp.AssemblyAngularVelocity) then return false, "bad_angular_velocity" end return true end local autoTarget = nil local autoTargetRaw = nil local autoUseGroundHeight = true local autoStopDist = 40 local lastTargetDist = nil local lastProgressAt = 0 local lastStuckWarnAt = -math.huge local lastHoldConfirmAt = 0 local lastCFrameNudgeAt = 0 local HOLD_CONFIRM_INTERVAL = 0.18 local CFRAME_NUDGE_INTERVAL = 0.08 local MIN_SERVER_STEP = 2 local RAYCAST_UP_BUFFER = 35 local lastGoodPosition = nil local lastSimRadiusRefreshAt = -math.huge local SIM_RADIUS_REFRESH_INTERVAL = 0.2 local lastNoCollideRefreshAt = -math.huge local NO_COLLIDE_REFRESH_INTERVAL = 0.12 local raycastParams = RaycastParams.new() raycastParams.FilterType = Enum.RaycastFilterType.Exclude local function adjustYAboveGround(pos) if not isUsablePos(pos) then return nil end local lp = game.Players.LocalPlayer raycastParams.FilterDescendantsInstances = { workspace:FindFirstChild("Enemies"), workspace:FindFirstChild("Characters"), lp.Character, } local up = math.max(config.height + RAYCAST_UP_BUFFER, 80) local origin = Vector3.new(pos.X, pos.Y + up, pos.Z) local hit = workspace:Raycast(origin, Vector3.new(0, -(up + 500), 0), raycastParams) if hit then return Vector3.new(pos.X, hit.Position.Y + config.height, pos.Z) end return pos end local function applyNoCollide(char) if not char then return end local now = os.clock() if now - lastNoCollideRefreshAt < NO_COLLIDE_REFRESH_INTERVAL then return end lastNoCollideRefreshAt = now for _, p in ipairs(char:GetDescendants()) do if p:IsA("BasePart") then if origCollide[p] == nil then origCollide[p] = p.CanCollide end if p.CanCollide then pcall(function() p.CanCollide = false end) end end end end local function restoreCollide() for p, orig in pairs(origCollide) do if p and p.Parent then pcall(function() p.CanCollide = orig end) end end origCollide = {} end local function attachBodyMovers(hrp) local ok = sanitizeHRP(hrp) if not ok then return false end local oldBP = hrp:FindFirstChild("BF_FlyBP") if oldBP then pcall(function() oldBP:Destroy() end) end local oldGyro = hrp:FindFirstChild("BF_FlyGyro") if oldGyro then pcall(function() oldGyro:Destroy() end) end local oldVel = hrp:FindFirstChild("BF_FlyBV") if oldVel then pcall(function() oldVel:Destroy() end) end bodyPos = Instance.new("BodyPosition") bodyPos.Name = "BF_FlyBP" bodyPos.MaxForce = Vector3.new(1, 1, 1) * 1e8 bodyPos.P = 6000 bodyPos.D = 700 bodyPos.Position = hrp.Position bodyPos.Parent = hrp bodyVel = Instance.new("BodyVelocity") bodyVel.Name = "BF_FlyBV" bodyVel.MaxForce = Vector3.new(1, 1, 1) * 1e8 bodyVel.P = 5000 bodyVel.Velocity = Vector3.zero bodyVel.Parent = hrp bodyGyro = Instance.new("BodyGyro") bodyGyro.Name = "BF_FlyGyro" bodyGyro.MaxTorque = Vector3.new(1, 1, 1) * 1e8 bodyGyro.P = 10000 bodyGyro.D = 500 local look = Vector3.new(0, 0, -1) if isFiniteCFrame(hrp.CFrame) and isFiniteVector3(hrp.CFrame.LookVector) then local flatLook = Vector3.new(hrp.CFrame.LookVector.X, 0, hrp.CFrame.LookVector.Z) if flatLook.Magnitude > 0.05 then look = flatLook.Unit end end bodyGyro.CFrame = CFrame.new(hrp.Position, hrp.Position + look) bodyGyro.Parent = hrp return true end local function detachBodyMovers() if bodyPos then pcall(function() bodyPos:Destroy() end); bodyPos = nil end if bodyVel then pcall(function() bodyVel:Destroy() end); bodyVel = nil end if bodyGyro then pcall(function() bodyGyro:Destroy() end); bodyGyro = nil end end local function saveHumanoidState(hum) origState.autoRotate = hum.AutoRotate origState.walkSpeed = hum.WalkSpeed origState.jumpPower = hum.JumpPower origState.platformStand = hum.PlatformStand end local function applyFlyState(hum) hum.AutoRotate = false hum.PlatformStand = false pcall(function() hum:ChangeState(Enum.HumanoidStateType.Freefall) end) end local function restoreHumanoidState(hum) if not hum then return end pcall(function() hum.AutoRotate = origState.autoRotate ~= nil and origState.autoRotate or true end) pcall(function() hum.PlatformStand = origState.platformStand ~= nil and origState.platformStand or false end) pcall(function() hum.Sit = false end) end local lastRaycastAt = 0 local RAYCAST_INTERVAL = 0.3 local hoverPos = nil local function keepCFrameAt(hrp, pos, velocity) if not isUsablePos(pos) then return end local ok = sanitizeHRP(hrp) if not ok then return end if velocity and not isFiniteVector3(velocity) then velocity = Vector3.zero end pcall(function() hrp.CFrame = CFrame.new(pos) * safeRotation(hrp) hrp.AssemblyLinearVelocity = velocity or Vector3.zero hrp.AssemblyAngularVelocity = Vector3.zero end) lastGoodPosition = pos end local function recoverBadHRPPosition(hrp, reason) if not hrp then return false end local recoverPos = nil if isUsablePos(autoTarget or autoTargetRaw) then recoverPos = autoTarget or autoTargetRaw elseif isUsablePos(hoverPos) then recoverPos = hoverPos elseif isUsablePos(lastGoodPosition) then recoverPos = lastGoodPosition end if not recoverPos then return false end pcall(function() hrp.CFrame = CFrame.new(recoverPos) hrp.AssemblyLinearVelocity = Vector3.zero hrp.AssemblyAngularVelocity = Vector3.zero end) if bodyPos then bodyPos.Position = recoverPos end if bodyVel then bodyVel.Velocity = Vector3.zero end if bodyGyro then bodyGyro.CFrame = CFrame.new(recoverPos, recoverPos + Vector3.new(0, 0, -1)) end lastGoodPosition = recoverPos warnPhysics("HRP 坐标异常(" .. tostring(reason) .. "), 已拉回飞行目标") return sanitizeHRP(hrp) end local function refreshSimulationRadius() local now = os.clock() if now - lastSimRadiusRefreshAt < SIM_RADIUS_REFRESH_INTERVAL then return end lastSimRadiusRefreshAt = now local lp = game.Players.LocalPlayer if type(sethiddenproperty) == "function" then pcall(function() sethiddenproperty(lp, "SimulationRadius", math.huge) end) pcall(function() sethiddenproperty(lp, "MaxSimulationRadius", math.huge) end) end end local function tick(dt) if _G.SP_BF_FLY_TOKEN ~= MODULE_TOKEN then M.off() return end if not running then return end local hrp = fm.getHRP() local hum = fm.getHumanoid() if not hrp or not hum then return end refreshSimulationRadius() local physicsOk, physicsReason = sanitizeHRP(hrp) if not physicsOk then if physicsReason == "bad_position" and recoverBadHRPPosition(hrp, physicsReason) then return end warnPhysics("HRP 物理状态异常(" .. tostring(physicsReason) .. "), 强制停止飞行等待角色恢复") M.off(true) return end if not bodyPos or not bodyPos.Parent or not bodyVel or not bodyVel.Parent then if not attachBodyMovers(hrp) then M.off(true) return end saveHumanoidState(hum) applyFlyState(hum) applyNoCollide(game.Players.LocalPlayer.Character) end local char = game.Players.LocalPlayer.Character applyNoCollide(char) if autoTargetRaw then if not isUsablePos(autoTargetRaw) then warn(TAG .. " autoTarget 坐标异常, 已清空") autoTargetRaw = nil autoTarget = nil return end local now = os.clock() if now - lastRaycastAt >= RAYCAST_INTERVAL then lastRaycastAt = now if autoUseGroundHeight then autoTarget = adjustYAboveGround(autoTargetRaw) or autoTargetRaw else autoTarget = autoTargetRaw end end local target = autoTarget or autoTargetRaw local dist = (target - hrp.Position).Magnitude if not lastTargetDist or dist < lastTargetDist - 2 then lastTargetDist = dist lastProgressAt = now end if dist <= autoStopDist then hoverPos = target bodyPos.Position = hoverPos if bodyVel then bodyVel.Velocity = Vector3.zero end lastTargetDist = dist lastProgressAt = now if now - lastHoldConfirmAt >= HOLD_CONFIRM_INTERVAL then keepCFrameAt(hrp, hoverPos) lastHoldConfirmAt = now end if bodyGyro then bodyGyro.CFrame = hrp.CFrame end return end local looksStuck = lastProgressAt > 0 and (now - lastProgressAt) > 1.2 if looksStuck and (now - lastStuckWarnAt) > 3 then lastStuckWarnAt = now warn(TAG .. " 移动确认慢: dist=" .. tostring(math.floor(dist)) .. " stop=" .. tostring(math.floor(autoStopDist))) end local dtSafe = math.max(tonumber(dt) or 0, 1 / 60) local delta = target - hrp.Position if not isFiniteVector3(delta) or delta.Magnitude < 0.05 then bodyPos.Position = target if bodyVel then bodyVel.Velocity = Vector3.zero end hoverPos = target return end local dir = delta.Unit local speed = math.min(config.autoSpeed or 100, dist / dtSafe) local velocity = dir * speed if not isFiniteVector3(velocity) then velocity = Vector3.zero end local step = math.min(dist, math.max(MIN_SERVER_STEP, speed * dtSafe)) local movePos = hrp.Position + dir * step if bodyVel then bodyVel.Velocity = velocity end bodyPos.Position = movePos if now - lastCFrameNudgeAt >= CFRAME_NUDGE_INTERVAL then keepCFrameAt(hrp, movePos, velocity) lastCFrameNudgeAt = now end hoverPos = movePos if bodyGyro then local lookAt = Vector3.new(target.X, hrp.Position.Y, target.Z) bodyGyro.CFrame = CFrame.new(hrp.Position, lookAt) end else if not hoverPos then hoverPos = adjustYAboveGround(hrp.Position) or hrp.Position end bodyPos.Position = hoverPos if bodyVel then bodyVel.Velocity = Vector3.zero end end end function M.on(opts) if shouldBlockFlyControl(opts) then logBlockedControl("阻止非当前海域流程启动飞行") return false end if running then return end local hrp = fm.getHRP() local hum = fm.getHumanoid() if not hrp or not hum then warn(TAG .. " 角色未就绪"); return end local physicsOk, physicsReason = sanitizeHRP(hrp) if not physicsOk then warn(TAG .. " HRP 物理状态异常(" .. tostring(physicsReason) .. "), 无法开启飞行"); return end running = true if not attachBodyMovers(hrp) then running = false return end saveHumanoidState(hum) applyFlyState(hum) origCollide = {} lastNoCollideRefreshAt = -math.huge applyNoCollide(game.Players.LocalPlayer.Character) local farmDriving = _G.bf_farm and _G.bf_farm.isRunning and _G.bf_farm.isRunning() or false local startTarget = farmDriving and hrp.Position or (adjustYAboveGround(hrp.Position) or hrp.Position) pcall(function() hrp.CFrame = CFrame.new(startTarget) * safeRotation(hrp) end) bodyPos.Position = startTarget lastGoodPosition = startTarget heartConn = RunService.Heartbeat:Connect(tick) local lp = game.Players.LocalPlayer if charConn then charConn:Disconnect(); charConn = nil end charConn = lp.CharacterAdded:Connect(function(char) if not running then return end local h = char:WaitForChild("Humanoid", 5) local r = char:WaitForChild("HumanoidRootPart", 5) if h and r then if not attachBodyMovers(r) then return end saveHumanoidState(h) applyFlyState(h) restoreCollide() origCollide = {} lastNoCollideRefreshAt = -math.huge applyNoCollide(char) end end) print(TAG .. " v3 自动驾驶 (离地 " .. config.height .. "m + 穿墙 + 服务端小步)") return true end function M.off(force) if not running then return end if not force and _G.bf_fly ~= M and _G.SP_BF_FLY_TOKEN ~= MODULE_TOKEN then running = false if heartConn then heartConn:Disconnect(); heartConn = nil end if charConn then charConn:Disconnect(); charConn = nil end bodyPos = nil bodyVel = nil bodyGyro = nil autoTarget = nil autoTargetRaw = nil autoUseGroundHeight = true lastHoldConfirmAt = 0 hoverPos = nil return end if not force and _G.bf_farm and _G.bf_farm.isRunning and _G.bf_farm.isRunning() then return end running = false if heartConn then heartConn:Disconnect(); heartConn = nil end if charConn then charConn:Disconnect(); charConn = nil end detachBodyMovers() autoTarget = nil autoTargetRaw = nil autoUseGroundHeight = true lastHoldConfirmAt = 0 lastCFrameNudgeAt = 0 lastNoCollideRefreshAt = -math.huge restoreCollide() restoreHumanoidState(fm.getHumanoid()) print(TAG .. " 飞行已关") end function M.setHeight(h, opts) if shouldBlockFlyControl(opts) then logBlockedControl("阻止非当前海域流程修改飞行高度") return false end config.height = math.max(MIN_SAFE_HEIGHT, tonumber(h) or 40) print(TAG .. " 离地高度=" .. config.height) return true end function M.setSpeed(s) config.autoSpeed = math.max(20, tonumber(s) or 100) end function M.getHeight() return config.height end function M.getSpeed() return config.autoSpeed end _G.SP_BF_CLEANUPS = _G.SP_BF_CLEANUPS or {} table.insert(_G.SP_BF_CLEANUPS, function() M.off(true) end) _G.SP_BF_DEV_VERBOSE = _G.SP_BF_DEV_VERBOSE == true local function devLog(msg) if _G.SP_BF_DEV_VERBOSE then print(TAG .. " [dev] " .. msg) end end function M.setAutoTarget(pos, opts) if not isUsablePos(pos) then warn(TAG .. " 忽略非法 autoTarget: " .. tostring(pos)) return end if (not opts or opts.owner == nil) and isProtectedUnownedTarget(pos) then rejectStaleTarget("阻止无 owner 的旧海域移动目标", pos) end if opts and opts.owner == "sea" and opts.token ~= _G.SP_BF_SEAS_TOKEN then rejectStaleTarget("阻止 token 失效的海域移动目标", pos) end if shouldBlockFlyControl(opts) then logBlockedControl("阻止非当前海域流程设置飞行目标") return false end local nextUseGroundHeight = not (opts and opts.useGroundHeight == false) local nextStopDist = opts and opts.stopDist or autoStopDist if opts and opts.speed then config.autoSpeed = opts.speed end if autoTargetRaw and (autoTargetRaw - pos).Magnitude < 0.25 and autoUseGroundHeight == nextUseGroundHeight and math.abs((autoStopDist or 0) - (nextStopDist or 0)) < 0.1 then autoStopDist = nextStopDist return end autoTargetRaw = pos autoTarget = nil autoUseGroundHeight = nextUseGroundHeight lastHoldConfirmAt = 0 lastRaycastAt = 0 lastTargetDist = nil lastProgressAt = os.clock() lastCFrameNudgeAt = 0 autoStopDist = nextStopDist if _G.SP_BF_DEV_VERBOSE then task.spawn(function() local hrp = fm.getHRP() if not hrp then return end local p0 = hrp.Position task.wait(1.5) if not autoTargetRaw or autoTargetRaw ~= pos then return end local p1 = fm.getHRP() and fm.getHRP().Position or p0 local moved = (p1 - p0).Magnitude local distToTarget = (pos - p1).Magnitude devLog(string.format("setAutoTarget(%d,%d,%d) 1.5s 后: moved=%dm  剩余=%dm", pos.X, pos.Y, pos.Z, moved, distToTarget)) end) end end function M.clearAutoTarget(opts) if shouldBlockFlyControl(opts) then logBlockedControl("阻止非当前海域流程清空飞行目标") return false end autoTargetRaw = nil autoTarget = nil autoUseGroundHeight = true lastHoldConfirmAt = 0 hoverPos = nil return true end function M.getAutoTarget() return autoTarget or autoTargetRaw end function M.toggle() if running then M.off() else M.on() end end function M.isRunning() return running end function M.stop() M.off(true) end function M.status() print(TAG .. " running=" .. tostring(running) .. " height=" .. config.height .. " speed=" .. math.floor(config.autoSpeed or 0) .. " autoTarget=" .. (autoTarget