local TAG = "[bf/farm]" local i18n = _G.bf_i18n local fm = _G.bf_fm local cfg = _G.bf_config local RunService = game:GetService("RunService") local M = {} local MODULE_TOKEN = {} _G.SP_BF_FARM_TOKEN = MODULE_TOKEN local running = false local paused = false local pauseReason = nil local connection = nil local state = "IDLE" local currentQuest = nil local currentIsland = nil local currentAnchor = nil local engagedAnchor = nil local questAccepted = false local lastTickTime = 0 local lastStartQuestTime = 0 local MOB_HUNT_RADIUS = 1500 local ANCHOR_ARRIVE_DIST = 8 local ENGAGE_KEEP_DIST = 32 local COMBAT_FLY_STOP_DIST = 4 local TICK_INTERVAL = 0.4 local START_QUEST_RETRY = 4 local IN_AREA_RADIUS = 250 local NPC_ARRIVE_DIST = 35 local SPAWN_ARRIVE_DIST = 45 local FARM_AREA_RADIUS = 160 local FARM_SEEK_RADIUS = 260 local FARM_CENTER_ARRIVE_DIST = 45 local QUEST_ZONE_MIN_DWELL = math.max(8, tonumber(cfg.QUEST_ZONE_MIN_DWELL) or 18) local QUEST_ZONE_EMPTY_DWELL = math.max(8, tonumber(cfg.QUEST_ZONE_EMPTY_DWELL) or 14) local maxSafeGatherRadius = math.max(10, math.min(500, tonumber(cfg.MAX_SAFE_GATHER_RADIUS) or 120)) local LOCAL_FARM_RADIUS = FARM_AREA_RADIUS local MAX_STACK_MOVE_SPEED = math.max(80, tonumber(cfg.MAX_FARM_STACK_SPEED) or 180) local MAX_COMBAT_MOVE_SPEED = math.max(60, tonumber(cfg.MAX_FARM_COMBAT_SPEED) or 120) local function clampMoveSpeed(kind, value, fallback) local n = tonumber(value) or fallback or 120 if kind == "stack" then n = math.min(n, MAX_STACK_MOVE_SPEED) end if kind == "combat" then n = math.min(n, MAX_COMBAT_MOVE_SPEED) end return math.max(20, n) end local moveSpeeds = { travel = clampMoveSpeed("travel", cfg.FARM_TRAVEL_SPEED, 180), stack = clampMoveSpeed("stack", cfg.FARM_STACK_SPEED, 360), combat = clampMoveSpeed("combat", cfg.FARM_COMBAT_SPEED, 90), } local TRAVEL_HOVER_HEIGHT = math.max(45, cfg.TRAVEL_HOVER_HEIGHT or 55) local COMBAT_HOVER_HEIGHT = math.max(20, math.min(55, cfg.COMBAT_HOVER_HEIGHT or cfg.HOVER_HEIGHT or 30)) local COMBAT_MIN_HOVER_HEIGHT = math.max(20, math.min(COMBAT_HOVER_HEIGHT, cfg.COMBAT_MIN_HOVER_HEIGHT or COMBAT_HOVER_HEIGHT)) local COMBAT_HEIGHT_RETRY_STEP = math.max(5, tonumber(cfg.COMBAT_HEIGHT_RETRY_STEP) or 10) local COMBAT_ACK_RETRY_TIMEOUT = math.max(1.2, tonumber(cfg.COMBAT_ACK_RETRY_TIMEOUT) or 2.2) local COMBAT_READY_PADDING = 12 local COMBAT_TARGET_READY_DIST = math.max(8, tonumber(cfg.COMBAT_TARGET_READY_DIST) or 12) local COMBAT_MAX_RESYNC = math.max(1, tonumber(cfg.COMBAT_MAX_RESYNC) or 2) local COMBAT_READY_STALL_TIMEOUT = math.max(1.5, tonumber(cfg.COMBAT_READY_STALL_TIMEOUT) or 3) local COMBAT_READY_STABLE_TIME = math.max(0, tonumber(cfg.COMBAT_READY_STABLE_TIME) or 0.8) local MISSING_STACK_STALL_TIMEOUT = math.max(1.5, tonumber(cfg.MISSING_STACK_STALL_TIMEOUT) or 2.5) local FARM_ANCHOR_STALL_TIMEOUT = math.max(20, tonumber(cfg.FARM_ANCHOR_STALL_TIMEOUT) or 35) local FARM_WATCHDOG_COOLDOWN = math.max(6, tonumber(cfg.FARM_WATCHDOG_COOLDOWN) or 12) local DAMAGE_LOG_INTERVAL = math.max(1.5, tonumber(cfg.FARM_DAMAGE_LOG_INTERVAL) or 3) local ownedByFarm = { bring = false, attack = false, fly = false } local stats = { ticks = 0, anchors_found = 0, anchors_killed = 0, quests_accepted = 0 } local tickBusy = false local lastQuestNudgeTime = -math.huge local lastQuestMismatchWarnTime = -math.huge local lastSpawnSeekLogTime = -math.huge local lastFarmTargetRepairLogTime = -math.huge local lastSafeHoldLogTime = -math.huge local stopOwnedCombatSubs local safeHold local clearAnchorWatch local questMode = false local lastQuestMode = nil local isUsablePos, horizontalDistance, enter local localFarmOrigin = nil local localFarmMobName = nil local questFarmOrigin = nil local questFarmSpawnName = nil local farmAreaState = { key = nil, kills = 0, selectedAt = -math.huge, emptySince = nil } local questProgressCur = nil local questProgressMax = nil local questProgressChangedAt = -math.huge local pendingUiKillAt = -math.huge local pendingUiKillName = nil local pendingUiKillPos = nil 