[kind] or moveSpeeds.travel or 120 end local function getTravelCap(kind, fallback) local n = tonumber(cfg[kind]) or fallback or getMoveSpeed("travel") return math.max(20, n) end local function getTravelSpeedTo(targetPos) local speed = getMoveSpeed("travel") local hrp = fm.getHRP() if not hrp or not isUsablePos(targetPos) then return speed end local dist = horizontalDistance(hrp.Position, targetPos) if dist >= 1500 then return math.min(speed, getTravelCap("FARM_LONG_TRAVEL_SPEED", 220)) end if dist >= 600 then return math.min(speed, getTravelCap("FARM_MID_TRAVEL_SPEED", 220)) end return speed end local function ensureFarmAreaTarget(farmCenter, stopDist, reason) if not isUsablePos(farmCenter) then return false end ensureFlyStart(TRAVEL_HOVER_HEIGHT) if not (_G.bf_fly and _G.bf_fly.isRunning and _G.bf_fly.isRunning() and _G.bf_fly.setAutoTarget) then return false end local targetPos = farmCenter + Vector3.new(0, 5, 0) _G.bf_fly.setAutoTarget(targetPos, { owner = "farm", stopDist = stopDist or FARM_CENTER_ARRIVE_DIST, speed = getTravelSpeedTo(farmCenter), }) if reason then local now = os.clock() if now - lastFarmTargetRepairLogTime >= 3 then lastFarmTargetRepairLogTime = now print(TAG .. string.format(" %s: target=(%d,%d,%d) speed=%d", reason, math.floor(targetPos.X), math.floor(targetPos.Y), math.floor(targetPos.Z), math.floor(getTravelSpeedTo(farmCenter)))) end end return true end local function repairMissingFarmAreaTarget(farmCenter) if state ~= "SEEK_FARM_AREA" or currentAnchor or not isUsablePos(farmCenter) then return end local hrp = fm.getHRP() if not hrp or horizontalDistance(hrp.Position, farmCenter) <= FARM_CENTER_ARRIVE_DIST then return end local target = _G.bf_fly and _G.bf_fly.getAutoTarget and _G.bf_fly.getAutoTarget() or nil if not isUsablePos(target) or horizontalDistance(target, farmCenter) > 35 then ensureFarmAreaTarget(farmCenter, FARM_CENTER_ARRIVE_DIST, "补发刷怪区导航目标") end end local function settleFarmAreaIfArrived(farmCenter) if state ~= "SEEK_FARM_AREA" or currentAnchor or not isUsablePos(farmCenter) then return end local hrp = fm.getHRP() if not hrp or horizontalDistance(hrp.Position, farmCenter) > FARM_CENTER_ARRIVE_DIST then return end enter("WAITING_SPAWN") stopOwnedCombatSubs() ensureFlyStart(TRAVEL_HOVER_HEIGHT) if _G.bf_fly and _G.bf_fly.clearAutoTarget then _G.bf_fly.clearAutoTarget() end print(TAG .. " 已到刷怪区域, 等待怪物刷新") end local function isAutoQuestEnabled() return _G.SP_BF_MODULES and _G.SP_BF_MODULES.auto_quest == true end local function isAutoFarmBringEnabled() return cfg.AUTO_FARM_BRING_ENABLED == true or (_G.SP_BF_MODULES and _G.SP_BF_MODULES.auto_farm_bring == true) end local function isSeaFlowRunning() if _G.bf_flow and _G.bf_flow.isLockedFor and _G.bf_flow.isLockedFor("farm") then return true end if _G.SP_BF_MODULES and _G.SP_BF_MODULES._sea_flow_active == true then return true end return _G.bf_seas and _G.bf_seas.isRunning and _G.bf_seas.isRunning() == true end local function getCurrentSeaNumber() local tag = cfg.SEA_BOUNDS and cfg.SEA_BOUNDS[game.PlaceId] or nil return tag and tonumber(tostring(tag):match("%d+")) or nil end local function handleAutoSeaTransition() if not questMode then return false end if isSeaFlowRunning() then currentAnchor = nil clearAnchorWatch() stopOwnedCombatSubs() if os.clock() - lastSafeHoldLogTime >= 5 then lastSafeHoldLogTime = os.clock() print(TAG .. " 海域流程执行中, AutoFarm 暂停让出移动控制") end return true end return false end safeHold = function(reason) local now = os.clock() if now - lastSafeHoldLogTime >= 5 then lastSafeHoldLogTime = now print(TAG .. " 安全停留: " .. tostring(reason)) end if _G.bf_fly and _G.bf_fly.clearAutoTarget then _G.bf_fly.clearAutoTarget() end stopOwnedCombatSubs() end local function pickBestQuest() local lv = fm.getLevel() local best, bestLv = nil, -1 local currentSeaNo = getCurrentSeaNumber() for _, sea in ipairs(cfg.SEA_GROUPS) do if not currentSeaNo or sea.sea == currentSeaNo then for _, q in ipairs(sea.quests) do if q.lv <= lv and q.lv > bestLv then best, bestLv = q, q.lv end end end end if lv < 14 then local lp = game.Players.LocalPlayer local teamName = lp and lp.Team and lp.Team.Name or "" if teamName == "Pirates" then return { n = "BanditQuest1", lv = 0, npc = "Bandit Quest Giver", island = "MarineStart" } end if teamName == "Marines" then return { n = "MarineQuest", lv = 0, npc = "Marine Leader", island = "MarineStart" } end local npcs = workspace:FindFirstChild("NPCs") local marine = npcs and npcs:FindFirstChild("Marine Recruiter") local bandit = npcs and npcs:FindFirstChild("Bandit Quest Giver") if marine and not bandit then return { n = "MarineQuest", lv = 0, npc = "Marine Recruiter", island = "MarineStart" } end if bandit and not marine then return { n = "BanditQuest1", lv = 0, npc = "Bandit Quest Giver", island = "MarineStart" } end if marine and bandit then local hrp = fm.getHRP() if hrp then local function npcDist(npc) local p = npc:FindFirstChild("HumanoidRootPart") or npc.PrimaryPart or npc:FindFirstChildWhichIsA("BasePart", true) return p and (p.Position - hrp.Position).Magnitude or math.huge end if npcDist(marine) <= npcDist(bandit) then return { n = "MarineQuest", lv = 0, npc = "Marine Recruiter", island = "MarineStart" } end return { n = "BanditQuest1", lv = 0, npc = "Bandit Quest Giver", island = "MarineStart" } end end end return best end local function getQuestTier(quest) return math.max(1, tonumber(quest and quest.tier) or 1) end local function getQuestKey(quest) if not quest then return "(none)" end return tostring(quest.n) .. ":" .. tostring(getQuestTier(quest)) end local function isFiniteNumber(n) return type(n) == "number" and n == n and n > -math.huge and n < math.huge end isUsablePos = function(pos) if typeof(pos) ~= "Vector3" then return false end if not isFiniteNumber(pos.X) or not isFiniteNumber(pos.Y) or not isFiniteNumber(pos.Z) then return false end if pos.Y < -1000 or pos.Y > 20000 then return false end if math.abs(pos.X) > 100000 or math.abs(pos.Z) > 100000 then return false end return true end horizontalDistance = function(a, b) if not isUsablePos(a) or not isUsablePos(b) then return math.huge end local dx = a.X - b.X local dz = a.Z - b.Z return math.sqrt(dx * dx + dz * dz) end local function getPos(x) if not x then return nil end if typeof(x) == "Vector3" then return isUsablePos(x) and x or nil end if typeof(x) == "CFrame" then return isUsablePos(x.Position) and x.Position or nil end if typeof(x) == "Instance" then if x:IsA("BasePart") then return isUsablePos(x.Position) and x.Position or nil end if x:IsA("Model") then local part = x:FindFirstChild("HumanoidRootPart") or x.PrimaryPart if part and isUsablePos(part.Position) then return part.Position end local ok, cf = pcall(function() return x:GetBoundingBox() end) if ok and cf and isUsablePos(cf.Position) then return cf.Position end end end return nil end local QUEST_NPC_HINTS = { BanditQuest1 = { "Bandit Quest Giver", "Quest Giver" }, MarineQuest = { "Marine Leader", "Marine Recruiter", "Quest Giver" }, MarineQuest2 = { "Marine Quest Giver", "Marine Lieutenant", "Quest Giver" }, PiratePortQuest = { "Pirate Port Quest Giver" }, DragonCrewQuest = { "Dragon Crew Quest Giver" }, VenomCrewQuest = { "Hydra Town Quest Giver" }, MarineTreeIsland = { "Marine Tree Quest Giver" }, DeepForestIsland3 = { "Turtle Adventure Quest Giver" }, DeepForestIsland = { "Deep Forest Quest Giver" }, DeepForestIsland2 = { "Deep Forest Area 2 Quest Giver", "Deep Forest Quest Giver" }, HauntedQuest1 = { "Haunted Castle Quest Giver 1", "Haunted Castle Quest Giver" }, HauntedQuest2 = { "Haunted Castle Quest Giver 2", "Haunted Castle Quest Giver" }, NutsIslandQuest = { "Peanut Quest Giver" }, IceCreamIslandQuest = { "Ice Cream Quest Giver" }, CakeQuest1 = { "Cake Quest Giver 1", "Cake Quest Giver" }, CakeQuest2 = { "Cake Quest Giver 2", "Cake Quest Giver" }, ChocQuest1 = { "Chocolate Quest Giver 1", "Chocolate Quest Giver" }, ChocQuest2 = { "Chocolate Quest Giver 2", "Chocolate Quest Giver" }, CandyQuest1 = { "