) if pos then return pos end end return nil end local function normalizeMobName(name) local s = tostring(name or "") s = s:gsub("%b[]", "") s = s:gsub("^%s+", ""):gsub("%s+$", "") return s:lower() end local function mobNameMatchesQuest(mobName, quest) local hints = getQuestMobHints(quest) if not hints then return true end local normalizedName = normalizeMobName(mobName) for _, hint in ipairs(hints) do if normalizedName == normalizeMobName(hint) then return true end end return false end local function questTextMatchesQuest(text, quest) local hints = getQuestMobHints(quest) if not hints then return true end local lowerText = tostring(text or ""):lower() for _, hint in ipairs(hints) do local h = tostring(hint or ""):lower() if lowerText:find(h, 1, true) or lowerText:find(h .. "s", 1, true) then return true end end return false end local function isBossMobName(mobName) local name = tostring(mobName or "") for _, boss in ipairs(cfg.BOSSES or {}) do if name == boss.name then return true end end return false end local function matchesCurrentQuestMob(mobName) if isBossMobName(mobName) then return false end if currentQuest then return mobNameMatchesQuest(mobName, currentQuest) end if localFarmMobName then return tostring(mobName or "") == localFarmMobName end return not isBossMobName(mobName) end local function questTextMatchesCurrent(text) if not currentQuest then return true end if not text or text == "" then return true end return questTextMatchesQuest(text, currentQuest) end local function findQuestSpawnPos(fromPos) if not currentQuest then return nil, math.huge, nil end if not getQuestMobHints(currentQuest) then return nil, math.huge, nil end local origin = workspace:FindFirstChild("_WorldOrigin") local spawns = origin and origin:FindFirstChild("EnemySpawns") local fallbackPos = getConfiguredQuestPos(currentQuest, { "spawn", "spawnPos", "mobPos" }) local fallbackName = getQuestMobHints(currentQuest)[1] if not spawns then if fallbackPos then return fallbackPos, horizontalDistance(fallbackPos, fromPos), fallbackName end return nil, math.huge, nil end local bestPos, bestDist, bestName = nil, math.huge, nil for _, inst in ipairs(spawns:GetDescendants()) do if inst:IsA("BasePart") and isUsablePos(inst.Position) and mobNameMatchesQuest(inst.Name, currentQuest) then local d = horizontalDistance(inst.Position, fromPos) if d < bestDist then bestPos, bestDist, bestName = inst.Position, d, inst.Name end end end if not bestPos and fallbackPos then return fallbackPos, horizontalDistance(fallbackPos, fromPos), fallbackName end return bestPos, bestDist, bestName end local function spawnZoneKey(pos) if not isUsablePos(pos) then return nil end local cell = 360 return tostring(math.floor(pos.X / cell)) .. ":" .. tostring(math.floor(pos.Z / cell)) end local function clearQuestFarmArea() questFarmOrigin = nil questFarmSpawnName = nil farmAreaState.key = nil farmAreaState.kills = 0 farmAreaState.selectedAt = -math.huge farmAreaState.emptySince = nil end local function setQuestFarmArea(pos, name, key) if not isUsablePos(pos) then return false end local nextKey = key or spawnZoneKey(pos) if nextKey ~= farmAreaState.key then farmAreaState.key = nextKey farmAreaState.kills = 0 farmAreaState.selectedAt = os.clock() farmAreaState.emptySince = nil end questFarmOrigin = pos questFarmSpawnName = name return true end local function getGatherRadius() return (_G.SP_BF_MODULES and _G.SP_BF_MODULES.gather_radius) or (cfg.DEFAULT_GATHER_RADIUS or 240) end local function getEffectiveGatherRadius() local requested = math.max(10, tonumber(getGatherRadius()) or (cfg.DEFAULT_GATHER_RADIUS or 240)) return math.min(requested, maxSafeGatherRadius) end local function getFarmAreaRadius() return math.max(FARM_AREA_RADIUS, math.min(200, getEffectiveGatherRadius() + 80)) end local function getFarmSeekRadius() return math.max(FARM_SEEK_RADIUS, getFarmAreaRadius() + 120) end local function getFarmZoneSearchRadius() return math.max(getFarmAreaRadius(), getEffectiveGatherRadius() + 