local TAG = "[bf/diag]" local fm = _G.bf_fm local M = {} local history = {} local MAX_HIST = 50 local function record(entry) table.insert(history, entry) while #history > MAX_HIST do table.remove(history, 1) end print(TAG .. " ★ " .. entry) end local function describe(v) local t = typeof(v) if t == "Instance" then return "<" .. v.ClassName .. ":" .. tostring(v.Name) .. ">" end if t == "table" then local n = 0; for _ in pairs(v) do n = n + 1 end return "<table×" .. n .. ">" end if t == "Vector3" or t == "CFrame" then return t end return t .. "(" .. tostring(v):sub(1, 40) .. ")" end local function dumpArgs(args, n) local parts = {} for i = 1, n do parts[i] = describe(args[i]) end return table.concat(parts, ", ") end local function isFiniteNumber(n) return type(n) == "number" and n == n and n > -math.huge and n < math.huge end local function isUsablePos(pos) if typeof(pos) ~= "Vector3" then return false end if not isFiniteNumber(pos.X) or not isFiniteNumber(pos.Y) or not isFiniteNumber(pos.Z) then return false end if pos.Y < -1000 or pos.Y > 20000 then return false end if math.abs(pos.X) > 100000 or math.abs(pos.Z) > 100000 then return false end return true end local function horizontalDistance(a, b) if not isUsablePos(a) or not isUsablePos(b) then return math.huge end local dx = a.X - b.X local dz = a.Z - b.Z return math.sqrt(dx * dx + dz * dz) end local function fmtPos(pos) if not isUsablePos(pos) then return "nil" end return string.format("(%d,%d,%d)", math.floor(pos.X), math.floor(pos.Y), math.floor(pos.Z)) end local function nearestEnemy(fromPos, maxDist) local enemies = workspace:FindFirstChild("Enemies") if not enemies or not isUsablePos(fromPos) then return nil, math.huge end local best, bestDist = nil, math.huge for _, mob in ipairs(enemies:GetChildren()) do local hum = mob:FindFirstChildOfClass("Humanoid") local hrp = mob:FindFirstChild("HumanoidRootPart") if hum and hum.Health > 0 and hrp and isUsablePos(hrp.Position) then local d = (hrp.Position - fromPos).Magnitude if d < bestDist and d <= (maxDist or 300) then best, bestDist = mob, d end end end return best, bestDist end local function networkOwnerText(part) if type(isnetworkowner) ~= "function" or not part then return "n/a" end local ok, res = pcall(isnetworkowner, part) if not ok then return "err" end return tostring(res) end local probeToken = 0 local function parseNumberList(input, defaults) local out = {} if type(input) == "table" then for _, v in ipairs(input) do local n = tonumber(v) if n then table.insert(out, n) end end elseif type(input) == "string" then for token in input:gmatch("[^,%s]+") do local n = tonumber(token) if n then table.insert(out, n) end end elseif type(input) == "number" then table.insert(out, input) end if #out == 0 then for _, v in ipairs(defaults or {}) do table.insert(out, v) end end return out end local function playerHealth() local hum = fm.getHumanoid() return hum and hum.Health or nil end local function ensureFarmRunning() if _G.bf_farm and _G.bf_farm.isRunning and not _G.bf_farm.isRunning() then _G.bf_farm.start() end end local function sampleEnemyDamage(lastHealth, maxDist) local result = { damage = 0, hits = 0, alive = 0 } local enemies = workspace:FindFirstChild("Enemies") local hrp = fm.getHRP() if not enemies or not hrp or not isUsablePos(hrp.Position) then return result end local fromPos = hrp.Position maxDist = maxDist or 360 for _, mob in ipairs(enemies:GetChildren()) do local hum = mob:FindFirstChildOfClass("Humanoid") local mhrp = mob:FindFirstChild("HumanoidRootPart") if hum and mhrp and isUsablePos(mhrp.Position) and (mhrp.Position - fromPos).Magnitude <= maxDist then local hp = hum.Health if hp > 0 then result.alive = result.alive + 1 end local prev = lastHealth[mob] if prev and hp < prev - 0.05 then result.damage = result.damage + (prev - hp) result.hits = result.hits + 1 end lastHealth[mob] = hp end end return result end local function isNetworkOwned(part) if type(isnetworkowner) ~= "function" or not part then return true end local ok, res = pcall(isnetworkowner, part) return ok and res == true end local function sampleGatherStats(stackPos, targetName, radius) local result = { candidates = 0, owned = 0, near = 0, farthest = 0 } local enemies = workspace:FindFirstChild("Enemies") if not enemies or not isUsablePos(stackPos) then return result end radius = math.max(10, tonumber(radius) or 80) for _, mob in ipairs(enemies:GetChildren()) do local hum = mob:FindFirstChildOfClass("Humanoid") local hrp = mob:FindFirstChild("HumanoidRootPart") if hum and hum.Health > 0 and hrp and isUsablePos(hrp.Position) and ((not targetName) or mob.Name == targetName) then local flat = horizontalDistance(hrp.Position, stackPos) if flat <= radius then result.candidates = result.candidates + 1 if isNetworkOwned(hrp) then result.owned = result.owned + 1 end if flat > result.farthest then result.farthest = flat end end if flat <= 28 then result.near = result.near + 1 end end end return result end local function waitForFarmEngage(timeout) local untilAt = os.clock() + (tonumber(timeout) or 8) local lastSnap = nil while os.clock() < untilAt do lastSnap = _G.bf_farm and _G.bf_farm.snapshot and _G.bf_farm.snapshot() or nil if lastSnap and lastSnap.state == "ENGAGE" and isUsablePos(lastSnap.stackPos) then return lastSnap end task.wait(0.2) end return lastSnap end local commfHookActive = false function M.startCommF() if commfHookActive then return end if type(hookmetamethod) ~= "function" then warn(TAG .. " 执行器不支持 hookmetamethod") return end commfHookActive = true local mt = getrawmetatable(game) local old = mt.__namecall setreadonly(mt, false) mt.__namecall = newcclosure(function(self, ...) if commfHookActive and self and self:IsA("RemoteFunction") and (self.Name == "CommF" or self.Name == "CommF_") then local method = getnamecallmethod() if method == "InvokeServer" then local args = { ... } local n = select("#", ...) local s = string.format("%s:%s(%s)", self.Name, method, dumpArgs(args, n)) record(s) end end return old(self, ...) end) setreadonly(mt, true) print(TAG .. " CommF hook 已开,现在请你在游戏里手动操作(买武器/加点/接任务等),会自动打印命令名") end function M.stopCommF() commfHookActive = false print(TAG .. " CommF hook 关闭(hook 本体保留,但不再记录)") end function M.recent(n) n = n or 20 local start = math.max(1, #history - n + 1) print(TAG .. " 最近 " .. (#history - start + 1) .. " 条:") for i = start, #history do print("  " .. i .. ". " .. history[i]) end end function M.clear() history = {} end function M.scanEnemies(maxDist) maxDist = maxDist or 1000 local enemies = workspace:FindFirstChild("Enemies") if not enemies then print(TAG .. " no Enemies folder"); return end local hrp = fm.getHRP() if not hrp then return end local groups = {} for _, m in ipairs(enemies:GetChildren()) do local mhrp = m:FindFirstChild("HumanoidRootPart") if mhrp then local d = (mhrp.Position - hrp.Position).Magnitude if d <= maxDist then local g = groups[m.Name] or { count = 0, minDist = math.huge, maxDist = 0 } g.count = g.count + 1 g.minDist = math.min(g.minDist, d) g.maxDist = math.max(g.maxDist, d) groups[m.Name] = g end end end print(TAG .. " enemies within " .. maxDist .. "m:") for name, g in pairs(groups) do print(string.format("  %s × %d (dist %d~%d)", name, g.count, g.minDist, g.maxDist)) end end function M.moveAck(seconds, interval, maxDist) seconds = math.max(1, tonumber(seconds) or 6) interval = math.max(0.2, tonumber(interval) or 0.5) maxDist = math.max(50, tonumber(maxDist) or 260) local startedAt = os.clock() local lastEnemyHealth = setmetatable({}, { __mode = "k" }) print(TAG .. string.format(" moveAck 开始: %.1fs interval=%.1fs maxDist=%dm", seconds, interval, maxDist)) task.spawn(function() local i = 0 while os.clock() - startedAt <= seconds do i = i + 1 local hrp = fm.getHRP() local hum = fm.getHumanoid() local playerPos = hrp and hrp.Position or nil local anchor = _G.bf_farm and _G.bf_farm.currentAnchor and _G.bf_farm.currentAnchor() or nil local target = anchor local targetDist = math.huge if target then local th = target:FindFirstChild("HumanoidRootPart") if th and playerPos then targetDist = (th.Position - playerPos).Magnitude end end if not target then target, targetDist = nearestEnemy(playerPos, maxDist) end local thum = target and target:FindFirstChildOfClass("Humanoid") or nil local thrp = target and target:FindFirstChild("HumanoidRootPart") or nil local enemyHp = thum and thum.Health or nil local prevHp = target and lastEnemyHealth[target] or nil if target and enemyHp then lastEnemyHealth[target] = enemyHp end local hpDelta = (prevHp and enemyHp) and (prevHp - enemyHp) or 0 local flat, dy = math.huge, 0 if playerPos and thrp and isUsablePos(thrp.Position) then flat = horizontalDistance(playerPos, thrp.Position) dy = playerPos.Y - thrp.Position.Y end local flyTarget = _G.bf_fly and _G.bf_fly.getAutoTarget and _G.bf_fly.getAutoTarget() or nil print(TAG .. string.format( " moveAck#%d php=%s pos=%s fly=%s target=%s ehp=%s d=%s flat=%s dy=%s dhp=%.1f owner=%s", i, hum and tostring(math.floor(hum.Health)) or "nil", fmtPos(playerPos), fmtPos(flyTarget), target and target.Name or "nil", enemyHp and tostring(math.floor(enemyHp)) or "nil", targetDist < math.huge and tostring(math.floor(targetDist)) or "nil", flat < math.huge and tostring(math.floor(flat)) or "nil", tostring(math.floor(dy)), hpDelta, networkOwnerText(thrp) )) task.wait(interval) end print(TAG .. " moveAck 结束") end) end function M.stopProbe() probeToken = probeToken + 1 print(TAG .. " speed probe stop requested") end function M.attackRateProbe(intervals, seconds) intervals = parseNumberList(intervals, { 0.5, 0.42, 0.35, 0.3, 0.25 }) seconds = math.max(4, tonumber(seconds) or 8) probeToken = probeToken + 1 local token = probeToken print(TAG .. string.format(" attackRateProbe 开始: intervals=%s seconds=%.1f", table.concat(intervals, ","), seconds)) task.spawn(function() ensureFarmRunning() local originalTick, originalSync = nil, nil if _G.bf_attack and _G.bf_attack.getAttackIntervals then originalTick, originalSync = _G.bf_attack.getAttackIntervals() end for _, interval in ipairs(intervals) do if token ~= probeToken then break end if _G.bf_attack and _G.bf_attack.setAttackIntervals then _G.bf_attack.setAttackIntervals(interval, interval) elseif _G.bf_attack and _G.bf_attack.setTickInterval then _G.bf_attack.setTickInterval(interval) end local hp0 = playerHealth() or 0 local lastHealth = setmetatable({}, { __mode = "k" }) sampleEnemyDamage(lastHealth, 420) local startedAt = os.clock() local damage, hits, activeSamples, samples = 0, 0, 0, 0 while token == probeToken and os.clock() - startedAt < seconds do local d = sampleEnemyDamage(lastHealth, 420) damage = damage + d.damage hits = hits + d.hits samples = samples + 1 local snap = _G.bf_farm and _G.bf_farm.snapshot and _G.bf_farm.snapshot() or nil if snap and snap.state == "ENGAGE" then activeSamples = activeSamples + 1 end task.wait(0.15) end local elapsed = math.max(0.1, os.clock() - startedAt) local hpDrop = math.max(0, hp0 - (playerHealth() or hp0)) local activeRatio = samples > 0 and (activeSamples / samples) or 0 local ok = damage > 0 and hpDrop < 1 print(TAG .. string.format( " attackProbe interval=%.2fs damage=%.1f dps=%.1f hits=%d active=%.0f%% hpDrop=%.1f ok=%s", interval, damage, damage / elapsed, hits, activeRatio * 100, hpDrop, tostring(ok))) task.wait(0.8) end if originalTick and _G.bf_attack and _G.bf_attack.setAttackIntervals then _G.bf_attack.setAttackIntervals(originalTick, originalSync or originalTick) end print(TAG .. " attackRateProbe 结束") end) end function M.farmSpeedProbe(speeds, seconds, attackInterval, combatSpeed) speeds = parseNumberList(speeds, { 120, 150, 180, 220, 260 }) seconds = math.max(6, tonumber(seconds) or 12) attackInterval = tonumber(attackInterval) combatSpeed = tonumber(combatSpeed) probeToken = probeToken + 1 local token = probeToken print(TAG .. string.format(" farmSpeedProbe 开始: speeds=%s seconds=%.1f attack=%s combat=%s", table.concat(speeds, ","), seconds, attackInterval and tostring(attackInterval) or "keep", combatSpeed and tostring(combatSpeed) or "keep")) task.spawn(function() ensureFarmRunning() if attackInterval and _G.bf_attack and _G.bf_attack.setAttackIntervals then _G.bf_attack.setAttackIntervals(attackInterval, attackInterval) end local originalSpeeds = _G.bf_farm and _G.bf_farm.getMoveSpeeds and _G.bf_farm.getMoveSpeeds() or nil local fixedCombat = combatSpeed or (originalSpeeds and originalSpeeds.combat) or 90 for _, speed in ipairs(speeds) do if token ~= probeToken then break end if _G.bf_farm and _G.bf_farm.setMoveSpeeds then _G.bf_farm.setMoveSpeeds(speed, speed, fixedCombat) end local snap0 = _G.bf_farm and _G.bf_farm.snapshot and _G.bf_farm.snapshot() or nil local kills0 = snap0 and snap0.stats and snap0.stats.anchors_killed or 0 local hp0 = playerHealth() or 0 local lastHealth = setmetatable({}, { __mode = "k" }) sampleEnemyDamage(lastHealth, 500) local startedAt = os.clock() local damage, hits, samples, engageSamples = 0, 0, 0, 0 local flightStartedAt, flights, flightTime = nil, 0, 0 local prevState = snap0 and snap0.state or nil while token == probeToken and os.clock() - startedAt < seconds do local snap = _G.bf_farm and _G.bf_farm.snapshot and _G.bf_farm.snapshot() or nil local state = snap and snap.state or nil if state == "FLY_TO_STACK" and prevState ~= "FLY_TO_STACK" then flightStartedAt = os.clock() elseif state == "ENGAGE" and prevState == "FLY_TO_STACK" and flightStartedAt then flights = flights + 1 flightTime = flightTime + (os.clock() - flightStartedAt) flightStartedAt = nil end prevState = state if state == "ENGAGE" then engageSamples = engageSamples + 1 end local d = sampleEnemyDamage(lastHealth, 500) damage = damage + d.damage hits = hits + d.hits samples = samples + 1 task.wait(0.2) end local snap1 = _G.bf_farm and _G.bf_farm.snapshot and _G.bf_farm.snapshot() or nil local kills1 = snap1 and snap1.stats and snap1.stats.anchors_killed or kills0 local hpDrop = math.max(0, hp0 - (playerHealth() or hp0)) local avgFlight = flights > 0 and (flightTime / flights) or 0 local engageRatio = samples > 0 and (engageSamples / samples) or 0 local ok = damage > 0 and hpDrop < 1 print(TAG .. string.format( " speedProbe speed=%d combat=%d damage=%.1f hits=%d kills=%d avgFly=%.2fs flights=%d engage=%.0f%% hpDrop=%.1f ok=%s", speed, fixedCombat, damage, hits, kills1 - kills0, avgFlight, flights, engageRatio * 100, hpDrop, tostring(ok))) task.wait(0.8) end if originalSpeeds and _G.bf_farm and _G.bf_farm.setMoveSpeeds then _G.bf_farm.setMoveSpeeds(originalSpeeds.travel, originalSpeeds.stack, originalSpeeds.combat) end print(TAG .. " farmSpeedProbe 结束") end) end function M.gatherRadiusProbe(radii, seconds) radii = parseNumberList(radii, { 80, 120, 160, 200, 240, 300 }) seconds = math.max(6, tonumber(seconds) or 10) probeToken = probeToken + 1 local token = probeToken print(TAG .. string.format(" gatherRadiusProbe 开始: radii=%s seconds=%.1f", table.concat(radii, ","), seconds)) task.spawn(function() ensureFarmRunning() local originalGather = _G.bf_farm and _G.bf_farm.getGatherSettings and _G.bf_farm.getGatherSettings() or nil for _, radius in ipairs(radii) do if token ~= probeToken then break end radius = math.max(10, math.min(500, tonumber(radius) or 80)) if _G.bf_farm and _G.bf_farm.setMaxGatherRadius then _G.bf_farm.setMaxGatherRadius(radius) end if _G.bf_farm and _G.bf_farm.setGatherRadius then _G.bf_farm.setGatherRadius(radius) else _G.SP_BF_MODULES = _G.SP_BF_MODULES or {} _G.SP_BF_MODULES.gather_radius = radius if _G.bf_bring and _G.bf_bring.setGatherRadius then _G.bf_bring.setGatherRadius(radius) end end local snap = waitForFarmEngage(12) local targetName = snap and (snap.localMob or snap.anchor) or nil local stackPos = snap and snap.stackPos or nil local hp0 = playerHealth() or 0 local lastHealth = setmetatable({}, { __mode = "k" }) sampleEnemyDamage(lastHealth, math.max(420, radius + 160)) local startedAt = os.clock() local engagedTime = 0 local deadline = startedAt + math.max(seconds * 4, 24) local samples, damage, hits = 0, 0, 0 local sumPulled, sumMissed, maxPulled, maxMissed = 0, 0, 0, 0 local maxCandidates, maxOwned, maxNear, farthest = 0, 0, 0, 0 while token == probeToken and engagedTime < seconds and os.clock() < deadline do local p, miss = 0, 0 local farmRunning = _G.bf_farm and _G.bf_farm.isRunning and _G.bf_farm.isRunning() if not farmRunning then break end snap = _G.bf_farm and _G.bf_farm.snapshot and _G.bf_farm.snapshot() or snap local isEngaged = snap and snap.state == "ENGAGE" and isUsablePos(snap.stackPos) if isEngaged then if _G.bf_fm and _G.bf_fm.call then p, miss = _G.bf_fm.call("BringTick") p, miss = tonumber(p) or 0, tonumber(miss) or 0 end if snap then stackPos = isUsablePos(snap.stackPos) and snap.stackPos or stackPos targetName = snap.localMob or snap.anchor or targetName end local gs = sampleGatherStats(stackPos, targetName, radius) if gs.candidates > maxCandidates then maxCandidates = gs.candidates end if gs.owned > maxOwned then maxOwned = gs.owned end if gs.near > maxNear then maxNear = gs.near end if gs.farthest > farthest then farthest = gs.farthest end if p > maxPulled then maxPulled = p end if miss > maxMissed then maxMissed = miss end sumPulled = sumPulled + p sumMissed = sumMissed + miss local d = sampleEnemyDamage(lastHealth, math.max(420, radius + 160)) damage = damage + d.damage hits = hits + d.hits samples = samples + 1 engagedTime = engagedTime + 0.2 end task.wait(0.2) end local elapsed = math.max(0.1, engagedTime) local hpDrop = math.max(0, hp0 - (playerHealth() or hp0)) local avgPulled = samples > 0 and (sumPulled / samples) or 0 local avgMissed = samples > 0 and (sumMissed / samples) or 0 local ok = samples > 0 and damage > 0 and hpDrop < 1 and maxMissed <= math.max(1, maxPulled) print(TAG .. string.format( " gatherProbe radius=%d samples=%d candidates=%d owned=%d nearMax=%d farthest=%dm pulled=%.1f/%d missed=%.1f/%d damage=%.1f dps=%.1f hits=%d hpDrop=%.1f ok=%s", radius, samples, maxCandidates, maxOwned, maxNear, math.floor(farthest), avgPulled, maxPulled, avgMissed, maxMissed, damage, damage / elapsed, hits, hpDrop, tostring(ok))) task.wait(0.8) end if originalGather and _G.bf_farm then if _G.bf_bring and _G.bf_bring.clearAnchor then _G.bf_bring.clearAnchor() end if _G.bf_farm.setMaxGatherRadius then _G.bf_farm.setMaxGatherRadius(originalGather.max) end if _G.bf_farm.setGatherRadius then _G.bf_farm.setGatherRadius(originalGather.requested) end end print(TAG .. " gatherRadiusProbe 结束") end) end function M.listIslands() local map = workspace:FindFirstChild("Map") if not map then print(TAG .. " no Map"); return end local names = {} for _, c in ipairs(map:GetChildren()) do table.insert(names, c.Name) end print(TAG .. " islands: " .. table.concat(names, ", ")) end function M.stop() M.stopCommF() end function M.status() print(TAG .. string.format(" commf=%s history=%d", tostring(commfHookActive), #history)) end _G.bf_diag = M print(TAG .. " loaded") return M]] __src["./modules/extra"] = [[
local TAG = "[bf/extra]" local i18n = _G.bf_i18n local fm = _G.bf_fm local cfg = _G.bf_config local Players = game:GetService("Players") local RunService = game:GetService("RunService") local VirtualUser = game:GetService("VirtualUser") local Lighting = game:GetService("Lighting") local okVim, VirtualInputManager = pcall(function() return game:GetService("VirtualInputManager") end) if not okVim then VirtualInputManager = nil end local M = {} local god = { running = false, healthConn = nil, heartConn = nil, charConn = nil, origMax = nil } function M.god_on() if god.running then return end god.running = true local function apply() local hum = fm.getHumanoid() if not hum then return end if not god.origMax then god.origMax = hum.MaxHealth end pcall(function() hum.MaxHealth = math.huge end) pcall(function() hum.Health = math.huge end) pcall(function() hum.BreakJointsOnDeath = false end) end apply() local function bindChar(char) local hum = char:WaitForChild("Humanoid", 5) if not hum then return end if god.healthConn then god.healthConn:Disconnect() end god.healthConn = hum.HealthChanged:Connect(function() if god.running then pcall(function() hum.Health = hum.MaxHealth end) end end) end local lp = Players.LocalPlayer if lp.Character then bindChar(lp.Character) end if god.charConn then god.charConn:Disconnect(); god.charConn = nil end god.charConn = lp.CharacterAdded:Connect(function(c) if god.running then bindChar(c) end end) if god.heartConn then god.heartConn:Disconnect() end god.heartConn = RunService.Heartbeat:Connect(function() if not god.running then return end local hum = fm.getHumanoid() if hum then pcall(function() hum.Health = hum.MaxHealth end) end end) print(TAG .. " " .. i18n("extra.god_on")) end function M.god_off() if not god.running then return end god.running = false if god.healthConn then god.healthConn:Disconnect(); god.healthConn = nil end if god.heartConn then god.heartConn:Disconnect(); god.heartConn = nil end if god.charConn then god.charConn:Disconnect(); god.charConn = nil end local hum = fm.getHumanoid() if hum and god.origMax then pcall(function() hum.MaxHealth = god.origMax end) end print(TAG .. " " .. i18n("extra.god_off")) end local counter = { running = false, conn = nil } function M.counter_on() if counter.running then return end counter.running = true local lastDodge = 0 counter.conn = RunService.Heartbeat:Connect(function() if not counter.running then return end local hrp = fm.getHRP() if not hrp then return end local now = tick() if now - lastDodge < 0.15 then return end local enemies = workspace:FindFirstChild("Enemies") if not enemies then return end local myPos = hrp.Position for _, m in ipairs(enemies:GetChildren()) do local mhrp = m:FindFirstChild("HumanoidRootPart") if mhrp then local d = (mhrp.Position - myPos).Magnitude if d < 8 then local dodgeTo = mhrp.Position + Vector3.new(0, 30, 0) pcall(function() hrp.CFrame = CFrame.new(dodgeTo) * (hrp.CFrame - hrp.CFrame.Position) end) lastDodge = now break end end end end) print(TAG .. " " .. i18n("extra.counter_on")) end function M.counter_off() if not counter.running then return end counter.running = false if counter.conn then counter.conn:Disconnect(); counter.conn = nil end print(TAG .. " " .. i18n("extra.counter_off")) end local perf = { running = false, disabled = {}, origFps = nil, origLight = nil } function M.perf_on() if perf.running then return end perf.running = true pcall(function() local s = settings() local Rendering = s and s.Rendering if Rendering then perf.origLight = Rendering.QualityLevel Rendering.QualityLevel = Enum.QualityLevel.Level01 end end) if type(setfpscap) == "function" then perf.origFps = 60 pcall(function() setfpscap(20) end) end for _, obj in ipairs(workspace:GetDescendants()) do if obj:IsA("ParticleEmitter") or obj:IsA("Trail") or obj:IsA("Beam") or obj:IsA("Smoke") or obj:IsA("Fire") or obj:IsA("Explosion") then if obj.Enabled then obj.Enabled = false perf.disabled[obj] = true end end end for _, c in ipairs(Lighting:GetChildren()) do if c:IsA("Sky") or c:IsA("Atmosphere") or c:IsA("Bloom") or c:IsA("DepthOfField") or c:IsA("SunRaysEffect") or c:IsA("BlurEffect") then pcall(function() c.Enabled = false end) perf.disabled[c] = true end end print(TAG .. " " .. i18n("extra.perf_on")) end function M.perf_off() if not perf.running then return end perf.running = false pcall(function() local s = settings() if s and s.Rendering and perf.origLight then s.Rendering.QualityLevel = perf.origLight end end) if type(setfpscap) == "function" then pcall(function() setfpscap(perf.origFps or 60) end) end for obj in pairs(perf.disabled) do pcall(function() obj.Enabled = true end) end perf.disabled = {} print(TAG .. " " .. i18n("extra.perf_off")) end local AFK_CLICK_INTERVAL = math.max(60, tonumber(cfg and cfg.AFK_CLICK_INTERVAL) or 570) local afk = { running = false, conn = nil, ticker = nil, lastClickAt = -math.huge, clickCount = 0 } local function getScreenClickPos() local cam = workspace.CurrentCamera local vp = cam and cam.ViewportSize or Vector2.new(800, 600) return Vector2.new(math.max(2, math.floor(vp.X - 8)), math.max(2, math.floor(vp.Y * 0.08))) end local function clickScreen(reason) local pos = getScreenClickPos() local method = "virtual_user" local ok = pcall(function() VirtualUser:CaptureController() VirtualUser:ClickButton2(Vector2.new(0, 0)) end) if not ok and VirtualInputManager then method = "corner_click" ok = pcall(function() VirtualInputManager:SendMouseButtonEvent(pos.X, pos.Y, 0, true, game, 0) task.wait(0.05) VirtualInputManager:SendMouseButtonEvent(pos.X, pos.Y, 0, false, game, 0) end) end if ok then afk.lastClickAt = os.clock() afk.clickCount = afk.clickCount + 1 print(TAG .. string.format(" Anti-AFK 输入 #%d (%s) via=%s @%d,%d", afk.clickCount, tostring(reason or "tick"), method, pos.X, pos.Y)) else warn(TAG .. " Anti-AFK 点击失败") end return ok end function M.afk_on() if afk.running then return end afk.running = true local lp = Players.LocalPlayer if lp.Idled then afk.conn = lp.Idled:Connect(function() if not afk.running then return end clickScreen("idled") end) end afk.ticker = task.spawn(function() while afk.running do task.wait(AFK_CLICK_INTERVAL) if not afk.running then break end clickScreen("timer") end end) task.spawn(function() task.wait(0.2) if afk.running and os.clock() - afk.lastClickAt > 5 then clickScreen("start") end end) print(TAG .. " " .. i18n("extra.afk_on") .. " interval=" .. tostring(AFK_CLICK_INTERVAL) .. "s") end function M.afk_off() if not afk.running then return end afk.running = false if afk.conn then afk.conn:Disconnect(); afk.conn = nil end if afk.ticker then pcall(function() task.cancel(afk.ticker) end); afk.ticker = nil end print(TAG .. " " .. i18n("extra.afk_off")) end function M.afk_click() return clickScreen("manual") end function M.afk_running() return afk.running end function M.stop() M.god_off() M.counter_off() M.perf_off() M.afk_off() end function M.status() print(TAG .. " god=" .. tostring(god.running) .. " counter=" .. tostring(counter.running) .. " perf=" .. tostring(perf.running) .. " afk=" .. tostring(afk.running) .. " afkClicks=" .. tostring(afk.clickCount) .. " afkInterval=" .. tostring(AFK_CLICK_INTERVAL)) end _G.bf_extra = M print(TAG .. " " .. i18n("loaded")) return M]] __src["./gui"] = [[
